{
  "name": "Anime GIF Gacha Battle",
  "description": "A 2.5D gacha card battler with daily Gemini-generated banners, custom GIF uploads, and flashy simulated 3D combat."
}

export enum AppScreen {
  TITLE = 'TITLE',
  HOME = 'HOME',
  GACHA = 'GACHA',
  BATTLE = 'BATTLE',
  DECK = 'DECK'
}

export enum Rarity {
  N = 'N',
  R = 'R',
  SR = 'SR',
  SSR = 'SSR',
  UR = 'UR'
}

export enum ElementType {
  FIRE = 'Fire',
  WATER = 'Water',
  EARTH = 'Earth',
  LIGHT = 'Light',
  DARK = 'Dark'
}

export interface CardData {
  id: string;
  name: string;
  rarity: Rarity;
  element: ElementType;
  imageUrl: string;
  hp: number;
  maxHp: number;
  attack: number;
  defense: number;
  description?: string;
  isCustom?: boolean;
}

export interface PlayerState {
  credits: number;
  pityCount: number;
  inventory: CardData[];
  level: number;
  exp: number;
}

export interface BannerData {
  date: string;
  featuredCards: Omit<CardData, 'id'>[];
}

import { Rarity } from './types';

export const GACHA_COST_SINGLE = 100;
export const GACHA_COST_TEN = 1000;
export const PITY_THRESHOLD = 100;

export const RARITY_RATES = {
  [Rarity.UR]: 0.01,  // 1%
  [Rarity.SSR]: 0.04, // 4%
  [Rarity.SR]: 0.15,  // 15%
  [Rarity.R]: 0.30,   // 30%
  [Rarity.N]: 0.50    // 50%
};

// Base stats multipliers
export const RARITY_STATS = {
  [Rarity.N]:   { hp: 100, atk: 20, def: 10 },
  [Rarity.R]:   { hp: 250, atk: 45, def: 20 },
  [Rarity.SR]:  { hp: 600, atk: 120, def: 50 },
  [Rarity.SSR]: { hp: 1500, atk: 350, def: 150 },
  [Rarity.UR]:  { hp: 3500, atk: 800, def: 400 }
};

export const FALLBACK_IMAGES = [
  'https://picsum.photos/id/1011/400/600',
  'https://picsum.photos/id/1012/400/600',
