];

import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity } from '../types';

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("No API Key found in process.env.API_KEY");
    return null;
  }

  const ai = new GoogleGenAI({ apiKey });

  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Make them sound powerful and fit for a card battle game.
    Provide realistic RPG stats based on rarity (UR: ~3500 HP, ~800 ATK, ~400 DEF. SSR: ~1500 HP, ~350 ATK, ~150 DEF).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: "Character Name" },
              rarity: { type: Type.STRING, description: "Must be exactly 'UR' or 'SSR'" },
              element: { type: Type.STRING, description: "One of: Fire, Water, Earth, Light, Dark" },
              description: { type: Type.STRING, description: "Short epic lore description" },
              hp: { type: Type.INTEGER },
              attack: { type: Type.INTEGER },
              defense: { type: Type.INTEGER }
            },
            required: ["name", "rarity", "element", "description", "hp", "attack", "defense"]
          }
        }
      }
    });

    if (response.text) {
      try {
        const parsed = JSON.parse(response.text);

        const featuredCards = parsed.map((c: any) => ({
          name: c.name,
          rarity: c.rarity as Rarity,
          element: c.element as ElementType,
          description: c.description,
          hp: c.hp,
          maxHp: c.hp,
          attack: c.attack,
          defense: c.defense,
          imageUrl: `https://picsum.photos/seed/${c.name.replace(/\s+/g, '')}/400/600` // Deterministic placeholder
        }));

        return {
          date: today,
          featuredCards
        };
      } catch (e) {
         console.error("Failed to parse Gemini JSON", e);
         return null;
      }
    }
    return null;
  } catch (error) {
    console.error("Error fetching from Gemini:", error);
    return null;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'gold';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  const baseStyle = "relative overflow-hidden font-bold rounded-lg shadow-[0_0_15px_rgba(0,0,0,0.5)] transition-all duration-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white border-2 border-blue-400 hover:shadow-[0_0_20px_rgba(59,130,246,0.8)]",
    secondary: "bg-slate-700 hover:bg-slate-600 text-slate-100 border-2 border-slate-500",
    danger: "bg-red-600 hover:bg-red-500 text-white border-2 border-red-400 hover:shadow-[0_0_20px_rgba(239,68,68,0.8)]",
    gold: "bg-yellow-600 hover:bg-yellow-500 text-yellow-50 border-2 border-yellow-300 hover:shadow-[0_0_25px_rgba(234,179,8,0.9)]"
  };

  const sizes = {
    sm: "px-3 py-1 text-sm",
    md: "px-6 py-2 text-md",
    lg: "px-8 py-4 text-xl tracking-wider"
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      <span className="relative z-10">{children}</span>
      {variant === 'gold' && (
        <div className="absolute inset-0 ur-glint opacity-50 pointer-events-none"></div>
      )}
    </button>
  );
};

import React from 'react';
import { CardData, Rarity } from '../types';

interface CardProps {
  card: CardData;
  size?: 'sm' | 'md' | 'lg';
  onClick?: () => void;
  className?: string;
  is3D?: boolean;
}

export const Card: React.FC<CardProps> = ({ card, size = 'md', onClick, className = '', is3D = false }) => {

  const rarityColors = {
    [Rarity.N]: 'from-gray-500 to-gray-700 border-gray-400',
    [Rarity.R]: 'from-blue-500 to-blue-800 border-blue-400',
    [Rarity.SR]: 'from-purple-500 to-purple-800 border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)]',
    [Rarity.SSR]: 'from-yellow-400 to-orange-600 border-yellow-300 shadow-[0_0_25px_rgba(234,179,8,0.7)]',
    [Rarity.UR]: 'from-red-500 via-pink-500 to-purple-600 border-red-300 shadow-[0_0_35px_rgba(239,68,68,0.9)] animate-pulse-fast'
  };

  const sizes = {
    sm: 'w-24 h-36 text-xs',
    md: 'w-48 h-72 text-sm',
    lg: 'w-64 h-96 text-base'
  };

  const isUR = card.rarity === Rarity.UR;

  return (
    <div 
      onClick={onClick}
      className={`
        relative rounded-xl overflow-hidden cursor-pointer transition-transform duration-300
        bg-gradient-to-br ${rarityColors[card.rarity]} border-4 
        ${sizes[size]} ${className}
        ${is3D ? 'transform hover:translate-z-10 hover:-translate-y-4 hover:rotate-y-12' : 'hover:-translate-y-2'}
      `}
      style={is3D ? { transformStyle: 'preserve-3d' } : {}}
    >
      {/* Background Image Container */}
      <div className="absolute inset-1 bg-black rounded-lg overflow-hidden">
        <img 
          src={card.imageUrl} 
          alt={card.name}
          className="w-full h-full object-cover opacity-80"
          onError={(e) => {
             // Fallback if image fails to load
             (e.target as HTMLImageElement).src = 'https://picsum.photos/400/600?grayscale';
          }}
        />
        {/* Inner gradient for readability */}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
      </div>

      {/* Card Content */}
      <div className="absolute inset-0 p-2 flex flex-col justify-between z-10 pointer-events-none">

        {/* Header */}
        <div className="flex justify-between items-start drop-shadow-md">
          <div className="bg-black/60 px-2 py-1 rounded border border-white/20">
             <span className="font-bold text-white">{card.element}</span>
          </div>
          <div className={`font-black text-lg px-2 rounded-bl-lg bg-black/80 ${isUR ? 'text-red-400' : 'text-white'}`}>
            {card.rarity}
          </div>
        </div>

        {/* Footer info */}
        <div className="mt-auto drop-shadow-[0_2px_2px_rgba(0,0,0,1)]">
          <h3 className={`font-black truncate ${size === 'sm' ? 'text-sm' : 'text-xl'} ${isUR ? 'text-yellow-300' : 'text-white'}`}>
            {card.name}
          </h3>
          {size !== 'sm' && (
            <div className="flex gap-2 mt-1 text-gray-200">
              <span className="bg-red-900/80 px-1 rounded">HP: {card.hp}</span>
              <span className="bg-orange-900/80 px-1 rounded">ATK: {card.attack}</span>
            </div>
          )}
        </div>
      </div>

      {/* UR specific glint effect overlay */}
      {isUR && <div className="absolute inset-0 ur-glint opacity-30 pointer-events-none z-20 mix-blend-overlay"></div>}
    </div>
  );
};

