  'https://images.unsplash.com/photo-1541562232579-512a21360020?auto=format&fit=crop&q=80&w=400&h=600',
  'https://images.unsplash.com/photo-1580477667995-2b92001ced15?auto=format&fit=crop&q=80&w=400&h=600',
  'https://images.unsplash.com/photo-1613376023733-0a73315d9b06?auto=format&fit=crop&q=80&w=400&h=600',
  'https://images.unsplash.com/photo-1560972550-aba3456b5564?auto=format&fit=crop&q=80&w=400&h=600'
];

import { FALLBACK_IMAGES } from '../constants';

export const getRandomAnimeImage = async (seed?: string): Promise<string> => {
  // Collection of anime and stylized image APIs
  const endpoints = [
    'https://api.waifu.pics/sfw/waifu',
    'https://api.waifu.pics/sfw/neko',
    'https://api.waifu.pics/sfw/shinobu',
    'https://nekos.best/api/v2/neko',
    'https://nekos.best/api/v2/waifu',
    'https://nekos.best/api/v2/husbando',
    'https://nekos.best/api/v2/kitsune'
  ];

  try {
    const endpoint = endpoints[Math.floor(Math.random() * endpoints.length)];
    const res = await fetch(endpoint, { cache: 'no-store' });
    const data = await res.json();

    // Support both waifu.pics and nekos.best response structures
    if (data.url) return data.url;
    if (data.results && data.results[0].url) return data.results[0].url;
  } catch (e) {
    console.warn("Anime API fetch failed, falling back...", e);
  }

  // Fallback to stylized seed avatars if API rate limited or offline
  if (seed) {
    return `https://api.dicebear.com/9.x/adventurer/svg?seed=${encodeURIComponent(seed)}&backgroundColor=b6e3f4,c0aede,d1d4f9,ffdfbf,ffd5dc`;
  }

  // Final static fallback
  return FALLBACK_IMAGES[Math.floor(Math.random() * FALLBACK_IMAGES.length)];
};

import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity } from '../types';
import { getRandomAnimeImage } from '../utils/animeImageApi';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("No API Key found in process.env.API_KEY");
    return null;
  }

  const ai = new GoogleGenAI({ apiKey });

  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Make them sound powerful and fit for a card battle game.
    Provide realistic RPG stats based on rarity (UR: ~3500 HP, ~800 ATK, ~400 DEF. SSR: ~1500 HP, ~350 ATK, ~150 DEF).
  `;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Character Name" },
                rarity: { type: Type.STRING, description: "Must be exactly 'UR' or 'SSR'" },
                element: { type: Type.STRING, description: "One of: Fire, Water, Earth, Light, Dark" },
                description: { type: Type.STRING, description: "Short epic lore description" },
                hp: { type: Type.INTEGER },
                attack: { type: Type.INTEGER },
                defense: { type: Type.INTEGER }
              },
              required: ["name", "rarity", "element", "description", "hp", "attack", "defense"]
            }
          }
        }
      });

      if (response.text) {
        try {
          const parsed = JSON.parse(response.text);

          const featuredCards = await Promise.all(parsed.map(async (c: any) => ({
            name: c.name,
            rarity: c.rarity as Rarity,
            element: c.element as ElementType,
            description: c.description,
            hp: c.hp,
            maxHp: c.hp,
            attack: c.attack,
            defense: c.defense,
            imageUrl: await getRandomAnimeImage(c.name)
          })));

          return {
            date: today,
            featuredCards
          };
        } catch (e) {
           console.warn("Failed to parse Gemini JSON output, falling back to default.", e);
           return null;
        }
      }
      return null;
    } catch (error: any) {
      const errorMsg = error?.message || String(error);
      const isRateLimit = errorMsg.includes('429') || 
                          errorMsg.includes('quota') || 
                          errorMsg.includes('RESOURCE_EXHAUSTED') ||
                          error?.status === 429;

      if (isRateLimit && attempt < 3) {
        const backoff = Math.pow(2, attempt) * 1000;
        console.warn(`API quota/rate limit reached. Retrying in ${backoff}ms...`);
        await sleep(backoff);
        continue;
      }

      console.warn("API request failed (Quota exceeded or other error). Using default offline fallback banner.");
      return null;
    }
  }

  return null;
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD } from '../constants';
import { fetchDailyBanner } from '../services/geminiService';
import { getRandomAnimeImage } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [loadingBanner, setLoadingBanner] = useState(true);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);

  useEffect(() => {
    const initBanner = async () => {
      setLoadingBanner(true);
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          if (parsed.date === today) {
            setBanner(parsed);
            setLoadingBanner(false);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      // Need new banner
      const newBanner = await fetchDailyBanner();
      if (newBanner) {
        setBanner(newBanner);
        localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
      } else {
        // Fallback banner if API fails or no key
        const fallbackImageUrl1 = await getRandomAnimeImage('CrimsonDemon');
        const fallbackImageUrl2 = await getRandomAnimeImage('AquaPaladin');
        const fallback: BannerData = {
          date: today,
          featuredCards: [
            { name: "Crimson Demon Lord", rarity: Rarity.UR, element: ElementType.FIRE, description: "A fiery demon from the abyss.", hp: 4000, maxHp: 4000, attack: 950, defense: 300, imageUrl: fallbackImageUrl1 },
            { name: "Aqua Paladin", rarity: Rarity.SSR, element: ElementType.WATER, description: "Defender of the deep seas.", hp: 2000, maxHp: 2000, attack: 400, defense: 500, imageUrl: fallbackImageUrl2 }
          ]
        };
        setBanner(fallback);
      }
      setLoadingBanner(false);
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    // Check if we rolled a featured banner character
    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         // 50% chance to be the banner character if we hit their rarity
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    // Generate generic card
    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2); // 90% to 110%

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      name: `Generic ${rollRarity} Warrior`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];

    // Calculate all rarities and stats synchronously to ensure exact pity handling
    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0; // Reset pity
      } else if (times === 10 && i === 9) {
        forceSR = true; // 10th pull guaranteed SR
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0; // Reset pity on ANY UR pull
      }
      baseCards.push(card);
    }

    // Fetch anime images concurrently
    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c) => {
        if (c.imageUrl) return c as CardData; // Keep banner image if already assigned
        const imageUrl = await getRandomAnimeImage(c.name + c.id);
        return { ...c, imageUrl } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      {/* Background with slight movement */}
      <div className="absolute inset-0 z-0 bg-[url('https://picsum.photos/id/1025/1920/1080')] bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen"></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto">

        {loadingBanner ? (
           <div className="text-2xl text-white animate-pulse">Communicating with AI to generate daily banner...</div>
        ) : !pullResults ? (
          <>
            {/* Banner Area */}
            {banner && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      {/* Fake ID for display */}
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Actions */}
            <div className="flex flex-col items-center gap-6 mt-auto">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          /* Results Screen */
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.3s_forwards]" />
                </div>
              ))}
            </div>
            <Button className="mt-12" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.5s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {/* Rolling Animation Overlay */}
        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn">
             <div className="flex flex-col items-center">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
}

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    // Enemy rarity trends up as player levels up
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 5), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];
    const name = `Rogue ${rarity} Entity`;

    const imageUrl = await getRandomAnimeImage(name + Date.now());

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: Math.floor(stats.hp * 1.2), // Enemy slight HP buff
      maxHp: Math.floor(stats.hp * 1.2),
      currentHp: Math.floor(stats.hp * 1.2),
      attack: stats.atk,
      defense: stats.def,
      shield: 0
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    // Fetch random enemy with anime image
    const enemy = await generateEnemyAsync();

    setPlayerCard({ ...selectedCard, currentHp: selectedCard.hp, shield: 0 });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated!"]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    // Trigger the dramatic VS flash
    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const handleAttack = () => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    executeTurn('ATTACK');
  };

  const handleDefend = () => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    executeTurn('DEFEND');
  };

  const executeTurn = (action: 'ATTACK' | 'DEFEND') => {
    setIsAnimating(true);

    // Player Action
    setTimeout(() => {
      if (action === 'DEFEND') {
        const shieldAmt = Math.floor(playerCard!.defense * 2);
        setPlayerCard(prev => ({ ...prev!, shield: shieldAmt }));
        addLog(`${playerCard!.name} guards, gaining ${shieldAmt} shield!`);
      } else {
        // Simple damage calc: ATK - DEF
        const dmg = Math.max(1, Math.floor(playerCard!.attack * (Math.random() * 0.4 + 0.8)) - Math.floor(enemyCard!.defense * 0.5));

        setEnemyCard(prev => {
           let remainingDmg = dmg;
           let newShield = prev!.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev!.currentHp - remainingDmg);
           return { ...prev!, shield: newShield, currentHp: newHp };
        });

        addLog(`${playerCard!.name} attacks for ${dmg} damage!`);
      }

      // Check win condition
      setEnemyCard(currentEnemy => {
         if (currentEnemy!.currentHp <= 0) {
           handleWin();
           return currentEnemy;
         }

         // Enemy Turn
         setTurn('ENEMY');
         setTimeout(() => {
           enemyAI(currentEnemy!);
         }, 1000);

         return currentEnemy;
      });

    }, 500); // Attack animation time
  };

  const enemyAI = (currentEnemy: Combatant) => {
     // Enemy AI: 80% attack, 20% defend
     const action = Math.random() > 0.2 ? 'ATTACK' : 'DEFEND';

     if (action === 'DEFEND') {
        const shieldAmt = Math.floor(currentEnemy.defense * 2);
        setEnemyCard(prev => ({ ...prev!, shield: shieldAmt }));
        addLog(`${currentEnemy.name} guards, gaining ${shieldAmt} shield!`);
        endEnemyTurn();
     } else {
        const dmg = Math.max(1, Math.floor(currentEnemy.attack * (Math.random() * 0.4 + 0.8)) - Math.floor(playerCard!.defense * 0.5));

        setPlayerCard(prev => {
           let remainingDmg = dmg;
           let newShield = prev!.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev!.currentHp - remainingDmg);

           if (newHp <= 0) {
             handleLose();
           } else {
             endEnemyTurn();
           }

           return { ...prev!, shield: newShield, currentHp: newHp };
        });
        addLog(`${currentEnemy.name} strikes back for ${dmg} damage!`);
     }
  };

  const endEnemyTurn = () => {
    setIsAnimating(false);
    setTurn('PLAYER');
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handleWin = () => {
    setPhase('RESULT');
    setIsAnimating(false);
    const expGain = 250;
    const creditGain = 500;

    setPlayerState(prev => {
      let newExp = prev.exp + expGain;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + creditGain,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  // Health Bar Component
  const HealthBar = ({ current, max, shield, name }: { current: number, max: number, shield: number, name: string }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span>{name}</span>
          <span>{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        {shield > 0 && (
          <div className="text-xs text-blue-300 mt-1 font-bold flex items-center gap-1">
            đź›ˇď¸Ź {shield} Shield
          </div>
        )}
      </div>
    );
  };

  if (phase === 'SELECT') {
