            { name: "Aqua Paladin", rarity: Rarity.SSR, element: ElementType.WATER, description: "Defender of the deep seas.", hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: fallbackImageUrl2 }
          ]
        };
        setBanner(fallback);
      }
      setLoadingBanner(false);
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    // Check if we rolled a featured banner character
    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         // 50% chance to be the banner character if we hit their rarity
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    // Generate generic card template (name overwritten later)
    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2); // 90% to 110%

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      name: `Generic ${rollRarity} Warrior`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];

    // Calculate all rarities and stats synchronously to ensure exact pity handling
    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0; // Reset pity
      } else if (times === 10 && i === 9) {
        forceSR = true; // 10th pull guaranteed SR
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0; // Reset pity on ANY UR pull
      }
      baseCards.push(card);
    }

    // Fetch unique AI names for any generic cards
    const uniqueNames = await generateAnimeNames(times);

    // Fetch anime images concurrently and assign AI names
    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c, i) => {
        if (c.imageUrl) {
           return c as CardData; // Keep banner character intact
        }

        const finalName = uniqueNames[i] || `Warrior ${i}`;
        const imageUrl = await getRandomAnimeImage(finalName + c.id);

        return { ...c, name: finalName, imageUrl } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      {/* Background with slight movement */}
      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto">

        {loadingBanner ? (
           <div className="text-2xl text-white animate-pulse">Communicating with AI to generate daily banner...</div>
        ) : !pullResults ? (
          <>
            {/* Banner Area */}
            {banner && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      {/* Fake ID for display */}
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Actions */}
            <div className="flex flex-col items-center gap-6 mt-auto">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          /* Results Screen */
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.3s_forwards]" />
                </div>
              ))}
            </div>
            <Button className="mt-12" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.5s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {/* Rolling Animation Overlay */}
        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn">
             <div className="flex flex-col items-center">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';
import { generateAnimeNames } from '../services/geminiService';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
}

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    // Enemy rarity trends up as player levels up
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 5), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    // Fetch unique name for boss enemy
    const generatedNames = await generateAnimeNames(1);
    const name = generatedNames[0] || `Rogue ${rarity} Entity`;

    const imageUrl = await getRandomAnimeImage(name + Date.now());

    // Enemy acts as a 'Boss', getting an HP buff (1.5x) to prevent quick OHKOs and force strategy
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    // Fetch random enemy with anime image
    const enemy = await generateEnemyAsync();

    setPlayerCard({ ...selectedCard, currentHp: selectedCard.hp, shield: 0 });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated!"]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    // Trigger the dramatic VS flash
    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const calculateDamage = (atk: number, def: number) => {
    // RPG scaling formula: Damage = ATK * (ATK / (ATK + DEF)) * Variance
    // This scales cleanly without causing 1-shots or 0 damage situations
    const baseDamage = (atk * atk) / (atk + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; // 85% to 115% damage
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const handleAttack = () => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    executeTurn('ATTACK');
  };

  const handleDefend = () => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    executeTurn('DEFEND');
  };

  const executeTurn = (action: 'ATTACK' | 'DEFEND') => {
    setIsAnimating(true);

    // Player Action
    setTimeout(() => {
      if (action === 'DEFEND') {
        // Shield based on max HP and defense to ensure it's significant
        const shieldAmt = Math.floor(playerCard!.maxHp * 0.15 + playerCard!.defense * 1.5);
        setPlayerCard(prev => ({ ...prev!, shield: shieldAmt }));
        addLog(`${playerCard!.name} takes a defensive stance! (+${shieldAmt} Shield)`);
      } else {
        const dmg = calculateDamage(playerCard!.attack, enemyCard!.defense);

        setEnemyCard(prev => {
           let remainingDmg = dmg;
           let newShield = prev!.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev!.currentHp - remainingDmg);
           return { ...prev!, shield: newShield, currentHp: newHp };
        });

        addLog(`${playerCard!.name} strikes for ${dmg} damage!`);
      }

      // Check win condition
      setEnemyCard(currentEnemy => {
         if (currentEnemy!.currentHp <= 0) {
           handleWin();
           return currentEnemy;
         }

         // Enemy Turn
         setTurn('ENEMY');
         setTimeout(() => {
           enemyAI(currentEnemy!);
         }, 1000);

         return currentEnemy;
      });

    }, 500); // Attack animation time
  };

  const enemyAI = (currentEnemy: Combatant) => {
     let action: 'ATTACK' | 'DEFEND' = 'ATTACK';
     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = playerCard!.currentHp + playerCard!.shield;

     // Lethal check: If average attack will kill the player, prioritize attacking
     const estimatedDmg = Math.floor((currentEnemy.attack * currentEnemy.attack) / (currentEnemy.attack + playerCard!.defense * 1.5));

     if (estimatedDmg >= playerEffectiveHp) {
        action = 'ATTACK';
     } 
     // Panic check: If low HP and no shield, heavily prioritize defending
     else if (hpPercent < 0.3 && currentEnemy.shield === 0) {
        action = Math.random() > 0.3 ? 'DEFEND' : 'ATTACK';
     } 
     // Standard behavior
     else {
        action = Math.random() > 0.25 ? 'ATTACK' : 'DEFEND';
     }

     if (action === 'DEFEND') {
        const shieldAmt = Math.floor(currentEnemy.maxHp * 0.15 + currentEnemy.defense * 1.5);
        setEnemyCard(prev => ({ ...prev!, shield: shieldAmt }));
        addLog(`${currentEnemy.name} guards fiercely! (+${shieldAmt} Shield)`);
        endEnemyTurn();
     } else {
        const dmg = calculateDamage(currentEnemy.attack, playerCard!.defense);

        setPlayerCard(prev => {
           let remainingDmg = dmg;
           let newShield = prev!.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev!.currentHp - remainingDmg);

           if (newHp <= 0) {
             handleLose();
           } else {
             endEnemyTurn();
           }

           return { ...prev!, shield: newShield, currentHp: newHp };
        });
        addLog(`${currentEnemy.name} attacks back for ${dmg} damage!`);
     }
  };

  const endEnemyTurn = () => {
    setIsAnimating(false);
    setTurn('PLAYER');
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handleWin = () => {
    setPhase('RESULT');
    setIsAnimating(false);
    const expGain = 250;
    const creditGain = 500;

    setPlayerState(prev => {
      let newExp = prev.exp + expGain;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + creditGain,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  // Health Bar Component
  const HealthBar = ({ current, max, shield, name }: { current: number, max: number, shield: number, name: string }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2">{name}</span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        {shield > 0 && (
          <div className="text-xs text-blue-300 mt-1 font-bold flex items-center gap-1">
            đź›ˇď¸Ź {shield} Shield
          </div>
        )}
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition">
                    <Card card={card} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        {/* Player Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={playerCard!.currentHp} max={playerCard!.maxHp} shield={playerCard!.shield} name={playerCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             <Card card={playerCard!} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />
          </div>
        </div>

        {/* VS text */}
        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        {/* Enemy Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={enemyCard!.currentHp} max={enemyCard!.maxHp} shield={enemyCard!.shield} name={enemyCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             <Card card={enemyCard!} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />
          </div>
        </div>

      </BattleStage>

      {/* UI Overlay Layer */}
      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        {/* Combat Log */}
        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-96 bg-black/40 backdrop-blur-md border border-white/10 rounded-lg p-2 max-h-32 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {/* Controls */}
        {phase === 'FIGHT' && !vsFlashing && (
          <div className="p-8 bg-gradient-to-t from-black via-black/80 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="max-w-xl mx-auto flex gap-4 justify-center">
              <Button 
                onClick={handleAttack} 
                disabled={turn !== 'PLAYER' || isAnimating}
                className="w-40 py-4 text-xl bg-red-600 hover:bg-red-500"
              >
                ATTACK
              </Button>
              <Button 
                onClick={handleDefend} 
                disabled={turn !== 'PLAYER' || isAnimating}
                variant="secondary"
                className="w-40 py-4 text-xl"
              >
                DEFEND
              </Button>
            </div>
            <div className="text-center mt-4 text-white font-bold tracking-widest uppercase text-xl animate-pulse">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>
          </div>
        )}

        {/* Result Screen */}
        {phase === 'RESULT' && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-50">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-6 uppercase tracking-widest ${playerCard!.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard!.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               {playerCard!.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Rewards</h3>
                   <div className="text-white text-lg font-bold text-green-400 mb-1">+500 Credits</div>
                   <div className="text-white text-lg font-bold text-blue-400">+250 EXP</div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>REBATTLE (Same Card)</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
