  changeScreen: (screen: AppScreen) => void;
}

export const DeckScreen: React.FC<DeckScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [filter, setFilter] = useState<Rarity | 'ALL'>('ALL');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;

      const elements = Object.values(ElementType);
      const element = elements[Math.floor(Math.random() * elements.length)];
      const stats = RARITY_STATS[Rarity.UR];

      const newCard: CardData = {
        id: `custom_${Date.now()}`,
        name: `Custom ${file.name.split('.')[0].substring(0, 10)}`,
        rarity: Rarity.UR,
        element: element,
        imageUrl: result,
        hp: stats.hp,
        maxHp: stats.hp,
        attack: stats.atk,
        defense: stats.def,
        isCustom: true,
        skills: generateProceduralSkills(element)
      };

      setPlayerState(prev => ({
        ...prev,
        inventory: [newCard, ...prev.inventory]
      }));
    };
    reader.readAsDataURL(file);
  };

  const filteredInventory = playerState.inventory.filter(c => filter === 'ALL' || c.rarity === filter);

  const rarityValues = { [Rarity.UR]: 5, [Rarity.SSR]: 4, [Rarity.SR]: 3, [Rarity.R]: 2, [Rarity.N]: 1 };
  filteredInventory.sort((a, b) => {
    if (rarityValues[b.rarity] !== rarityValues[a.rarity]) {
      return rarityValues[b.rarity] - rarityValues[a.rarity];
    }
    return b.id.localeCompare(a.id);
  });

  return (
    <div className="relative w-full h-full bg-slate-900 flex flex-col">
      {bgUrl && (
        <div 
          className="absolute inset-0 z-0 bg-cover bg-center opacity-20 mix-blend-overlay transition-all duration-1000" 
          style={{ backgroundImage: `url(${bgUrl})` }}
        ></div>
      )}

      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="MY DECK" />

      <div className="relative z-10 flex-1 flex flex-col pt-24 px-8 pb-8 overflow-hidden">

        <div className="flex justify-between items-center mb-6 bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-xl">
          <div className="flex gap-2">
            {['ALL', Rarity.UR, Rarity.SSR, Rarity.SR, Rarity.R, Rarity.N].map(r => (
              <button 
                key={r}
                onClick={() => setFilter(r as any)}
                className={`px-4 py-1 rounded font-bold text-sm ${filter === r ? 'bg-blue-600 text-white' : 'bg-slate-700 text-gray-400 hover:bg-slate-600'}`}
              >
                {r}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <input 
              type="file" 
              accept="image/png, image/jpeg, image/gif" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
            />
            <Button variant="secondary" size="sm" onClick={() => fileInputRef.current?.click()}>
               IMPORT .GIF / .PNG
            </Button>
            <div className="text-gray-400 text-sm">
              Total Cards: {playerState.inventory.length}
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-4 pb-12">
          {filteredInventory.length === 0 ? (
            <div className="h-full flex items-center justify-center text-gray-500 text-xl font-bold">
              NO CARDS FOUND
            </div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
              {filteredInventory.map(card => (
                <Card key={card.id} card={card} size="sm" />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity, Skill, SkillType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';
import { generateCardProfiles, generateProceduralSkills } from '../services/geminiService';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
  cooldowns: Record<SkillType, number>;
}

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  // Inject skills to legacy cards that don't have them
  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 5), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    // Fetch unique profile for enemy
    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element);

    const imageUrl = await getRandomAnimeImage(name + Date.now());

    // Enemy acts as a 'Boss', getting an HP buff (1.5x)
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated!"]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; // Guard
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    setIsAnimating(true);

    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCard! : enemyCard!;
    const defender = isPlayer ? enemyCard! : playerCard!;
    const setAttacker = isPlayer ? setPlayerCard : setEnemyCard;
    const setDefender = isPlayer ? setEnemyCard : setPlayerCard;

    // Apply specific skill mechanics
    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;

    switch (skill.type) {
      case SkillType.BASIC:
        dmgMultiplier = 1.0;
        break;
      case SkillType.HEAVY:
        dmgMultiplier = 1.8;
        newCooldown = 2;
        break;
      case SkillType.DEFEND:
        dmgMultiplier = 0; // Pure defend
        shieldMultiplier = 1.5;
        newCooldown = 2;
        break;
      case SkillType.ULTIMATE:
        dmgMultiplier = 2.5;
        shieldMultiplier = 1.0;
        newCooldown = 4;
        break;
    }

    setTimeout(() => {
      // Apply Cooldowns & Shields
      setAttacker((prev: any) => {
        const nextCooldowns = { ...prev.cooldowns };
        // Decrease all cooldowns by 1
        (Object.keys(nextCooldowns) as SkillType[]).forEach(k => {
           if (nextCooldowns[k] > 0) nextCooldowns[k] -= 1;
        });
        nextCooldowns[skill.type] = newCooldown; // Set used skill CD

        let generatedShield = prev.shield;
        if (shieldMultiplier > 0) {
           generatedShield += Math.floor(prev.maxHp * 0.10 + prev.defense * shieldMultiplier);
        }
        return { ...prev, cooldowns: nextCooldowns, shield: generatedShield };
      });

      // Apply Damage
      if (dmgMultiplier > 0) {
        const dmg = calculateDamage(attacker.attack, defender.defense, dmgMultiplier);

        setDefender((prev: any) => {
           let remainingDmg = dmg;
           let newShield = prev.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev.currentHp - remainingDmg);
           return { ...prev, shield: newShield, currentHp: newHp };
        });

        addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
      } else {
        addLog(`${attacker.name} uses [${skill.name}], guarding intensely!`);
      }

      // Check win/loss or pass turn
      setTimeout(() => {
        if (isPlayer) {
          setEnemyCard(curr => {
            if (curr!.currentHp <= 0) {
              handleWin();
            } else {
              setTurn('ENEMY');
              setTimeout(() => enemyAI(curr!), 1000);
            }
            return curr;
          });
        } else {
          setPlayerCard(curr => {
            if (curr!.currentHp <= 0) {
              handleLose();
            } else {
              setIsAnimating(false);
              setTurn('PLAYER');
            }
            return curr;
          });
        }
      }, 500);

    }, 500); // Attack animation timing
  };

  const enemyAI = (currentEnemy: Combatant) => {
     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = playerCard!.currentHp + playerCard!.shield;

     // Get available skills
     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!; // Fallback

     // 1. Lethal check
     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, playerCard!.defense, 1.8);
     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     // 2. Ultimate Ready
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     // 3. Survival Panic
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     // 4. Break Player Shield
     else if (playerCard!.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     // 5. Standard Random Selection
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handleWin = () => {
    setPhase('RESULT');
    setIsAnimating(false);
    const expGain = 250;
    const creditGain = 500;

    setPlayerState(prev => {
      let newExp = prev.exp + expGain;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + creditGain,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const HealthBar = ({ current, max, shield, name }: { current: number, max: number, shield: number, name: string }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2">{name}</span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        {shield > 0 && (
          <div className="text-xs text-blue-300 mt-1 font-bold flex items-center gap-1">
            đź›ˇď¸Ź {shield} Shield
          </div>
        )}
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={playerCard!.currentHp} max={playerCard!.maxHp} shield={playerCard!.shield} name={playerCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             <Card card={playerCard!} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={enemyCard!.currentHp} max={enemyCard!.maxHp} shield={enemyCard!.shield} name={enemyCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             <Card card={enemyCard!} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard!.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                // Determine button color style by skill type
                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-20 flex flex-col items-center justify-center ${btnStyle} relative`}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70">{skill.type}</span>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-2xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-50">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-6 uppercase tracking-widest ${playerCard!.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard!.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               {playerCard!.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Rewards</h3>
                   <div className="text-white text-lg font-bold text-green-400 mb-1">+500 Credits</div>
                   <div className="text-white text-lg font-bold text-blue-400">+250 EXP</div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>REBATTLE (Same Card)</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

export enum AppScreen {
  TITLE = 'TITLE',
  HOME = 'HOME',
  GACHA = 'GACHA',
  BATTLE = 'BATTLE',
  DECK = 'DECK'
}

export enum Rarity {
  N = 'N',
  R = 'R',
  SR = 'SR',
  SSR = 'SSR',
  UR = 'UR'
}

export enum ElementType {
  FIRE = 'Fire',
  WATER = 'Water',
  EARTH = 'Earth',
  LIGHT = 'Light',
  DARK = 'Dark'
}

export enum SkillType {
  BASIC = 'BASIC',
  HEAVY = 'HEAVY',
  DEFEND = 'DEFEND',
  ULTIMATE = 'ULTIMATE'
}

export interface Skill {
  name: string;
  type: SkillType;
  description: string;
}

export interface CardData {
  id: string;
  name: string;
  rarity: Rarity;
  element: ElementType;
  imageUrl: string;
  hp: number;
  maxHp: number;
  attack: number;
  defense: number;
  description?: string;
  isCustom?: boolean;
  skills?: Skill[];
}

export interface PlayerState {
  credits: number;
  pityCount: number;
  inventory: CardData[];
  level: number;
  exp: number;
}

export interface BannerData {
  date: string;
  featuredCards: Omit<CardData, 'id'>[];
}

import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity, SkillType, Skill } from '../types';
import { getRandomAnimeImage } from '../utils/animeImageApi';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const generateProceduralName = () => {
  const titles = ["Vanguard", "Ronin", "Striker", "Warlord", "Phantom", "Oracle", "Behemoth", "Tempest", "Wraith", "Paladin"];
  const prefixes = ["Crimson", "Mecha", "Void", "Astral", "Savage", "Divine", "Cyber", "Abyssal", "Iron", "Storm"];
  const randomSuffix = Math.floor(Math.random() * 999);
  return `${prefixes[Math.floor(Math.random() * prefixes.length)]}-${titles[Math.floor(Math.random() * titles.length)]} v${randomSuffix}`;
};

export const generateProceduralSkills = (element: ElementType): Skill[] => {
  const elementalPrefixes: Record<ElementType, string[]> = {
    [ElementType.FIRE]: ["Crimson", "Inferno", "Blaze", "Scorching", "Ember"],
    [ElementType.WATER]: ["Aqua", "Tidal", "Frost", "Abyssal", "Crystal"],
    [ElementType.EARTH]: ["Terra", "Gaia", "Quake", "Stone", "Iron"],
    [ElementType.LIGHT]: ["Radiant", "Holy", "Lumina", "Aegis", "Divine"],
    [ElementType.DARK]: ["Shadow", "Void", "Abyss", "Phantom", "Doom"]
  };
  const pre = elementalPrefixes[element];
  const p = () => pre[Math.floor(Math.random() * pre.length)];

  return [
    { type: SkillType.BASIC, name: `${p()} Strike`, description: "Deals standard elemental damage to the target." },
    { type: SkillType.HEAVY, name: `${p()} Buster`, description: "A powerful blow dealing 1.8x damage. (2-turn CD)" },
    { type: SkillType.DEFEND, name: `${p()} Guard`, description: "Raises a massive shield block based on max HP. (2-turn CD)" },
    { type: SkillType.ULTIMATE, name: `Absolute ${p()} Nova`, description: "Devastating ultimate attack dealing 2.5x damage. (4-turn CD)" }
  ];
};

export interface CardProfile {
  name: string;
  description: string;
  skills: Skill[];
}

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;

  const ai = new GoogleGenAI({ apiKey });
  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Give them highly unique, cool, and action-packed names (e.g. "Crimson Vanguard", "Mecha-Ronin 77", "Vortex Striker"). Do not use generic names.
    Provide a short, epic character summary/lore description.
    Also provide 4 distinct skill names for each fitting their element, along with a short description of what the skill does mechanically.
    Provide realistic RPG stats based on rarity (UR: ~15000 HP, ~850 ATK, ~450 DEF. SSR: ~6000 HP, ~350 ATK, ~200 DEF).
  `;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                rarity: { type: Type.STRING },
                element: { type: Type.STRING },
                description: { type: Type.STRING },
                hp: { type: Type.INTEGER },
                attack: { type: Type.INTEGER },
                defense: { type: Type.INTEGER },
                skillBasicName: { type: Type.STRING },
                skillBasicDesc: { type: Type.STRING },
                skillHeavyName: { type: Type.STRING },
                skillHeavyDesc: { type: Type.STRING },
                skillDefendName: { type: Type.STRING },
                skillDefendDesc: { type: Type.STRING },
                skillUltimateName: { type: Type.STRING },
                skillUltimateDesc: { type: Type.STRING }
              },
              required: ["name", "rarity", "element", "description", "hp", "attack", "defense", "skillBasicName", "skillBasicDesc", "skillHeavyName", "skillHeavyDesc", "skillDefendName", "skillDefendDesc", "skillUltimateName", "skillUltimateDesc"]
            }
          }
        }
      });

      if (response.text) {
        try {
          const parsed = JSON.parse(response.text);
          const featuredCards = await Promise.all(parsed.map(async (c: any) => {
            const el = Object.values(ElementType).includes(c.element) ? c.element as ElementType : ElementType.LIGHT;
            return {
              name: c.name,
              rarity: c.rarity as Rarity,
              element: el,
              description: c.description,
              hp: c.hp,
              maxHp: c.hp,
              attack: c.attack,
              defense: c.defense,
              imageUrl: await getRandomAnimeImage(c.name),
              skills: [
                { type: SkillType.BASIC, name: c.skillBasicName, description: c.skillBasicDesc },
                { type: SkillType.HEAVY, name: c.skillHeavyName, description: c.skillHeavyDesc },
                { type: SkillType.DEFEND, name: c.skillDefendName, description: c.skillDefendDesc },
                { type: SkillType.ULTIMATE, name: c.skillUltimateName, description: c.skillUltimateDesc }
              ]
            };
          }));
          return { date: today, featuredCards };
        } catch (e) {
           console.warn("Parse error", e);
        }
      }
    } catch (error: any) {
      if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }
  return null;
};

export const generateCardProfiles = async (count: number, elements: ElementType[]): Promise<CardProfile[]> => {
  const apiKey = process.env.API_KEY;

  const fallbackProfiles = elements.map(el => ({
    name: generateProceduralName(),
    description: `A mysterious warrior of the ${el} element, forged in battles unknown.`,
    skills: generateProceduralSkills(el)
  }));

  if (!apiKey) return fallbackProfiles;

  const ai = new GoogleGenAI({ apiKey });
  const elementsStr = elements.join(', ');
  const prompt = `Generate exactly ${count} unique anime character profiles matching these elements in order: [${elementsStr}]. 
  For each character:
  1. Provide a highly unique, cool, and action-packed specific name (e.g., 'Crimson Vanguard', 'Mecha-Ronin 77', 'Vortex Striker'). Avoid generic names.
  2. Provide a short, epic character summary/lore description.
  3. Provide 4 epic and uniquely named combat skills that match their element: 1 basic attack, 1 heavy attack, 1 defensive move, and 1 ultimate move.
  4. Include a short description for what each skill does.`;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                basicAttackName: { type: Type.STRING },
                basicAttackDesc: { type: Type.STRING },
                heavyAttackName: { type: Type.STRING },
                heavyAttackDesc: { type: Type.STRING },
                defensiveSkillName: { type: Type.STRING },
                defensiveSkillDesc: { type: Type.STRING },
                ultimateSkillName: { type: Type.STRING },
                ultimateSkillDesc: { type: Type.STRING }
              },
              required: ["name", "description", "basicAttackName", "basicAttackDesc", "heavyAttackName", "heavyAttackDesc", "defensiveSkillName", "defensiveSkillDesc", "ultimateSkillName", "ultimateSkillDesc"]
            }
          }
        }
      });

      if (response.text) {
         try {
           const profiles = JSON.parse(response.text);
           if (Array.isArray(profiles) && profiles.length >= count) {
              return profiles.slice(0, count).map((p: any) => ({
                name: p.name,
                description: p.description,
                skills: [
                  { type: SkillType.BASIC, name: p.basicAttackName, description: p.basicAttackDesc },
                  { type: SkillType.HEAVY, name: p.heavyAttackName, description: p.heavyAttackDesc },
                  { type: SkillType.DEFEND, name: p.defensiveSkillName, description: p.defensiveSkillDesc },
                  { type: SkillType.ULTIMATE, name: p.ultimateSkillName, description: p.ultimateSkillDesc }
                ]
              }));
           }
         } catch(e) {
           console.warn("Failed to parse profile json", e);
         }
      }
    } catch (error: any) {
       if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }

  return fallbackProfiles;
};

