interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
  cooldowns: Record<SkillType, number>;
}

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 5), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element);

    const imageUrl = await getRandomAnimeImage(name + Date.now());

    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated!"]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; 
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    setIsAnimating(true);

    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCard! : enemyCard!;
    const defender = isPlayer ? enemyCard! : playerCard!;
    const setAttacker = isPlayer ? setPlayerCard : setEnemyCard;
    const setDefender = isPlayer ? setEnemyCard : setPlayerCard;

    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;

    switch (skill.type) {
      case SkillType.BASIC:
        dmgMultiplier = 1.0;
        break;
      case SkillType.HEAVY:
        dmgMultiplier = 1.8;
        newCooldown = 2;
        break;
      case SkillType.DEFEND:
        dmgMultiplier = 0; 
        shieldMultiplier = 1.5;
        newCooldown = 2;
        break;
      case SkillType.ULTIMATE:
        dmgMultiplier = 2.5;
        shieldMultiplier = 1.0;
        newCooldown = 4;
        break;
    }

    setTimeout(() => {
      setAttacker((prev: any) => {
        const nextCooldowns = { ...prev.cooldowns };
        (Object.keys(nextCooldowns) as SkillType[]).forEach(k => {
           if (nextCooldowns[k] > 0) nextCooldowns[k] -= 1;
        });
        nextCooldowns[skill.type] = newCooldown;

        let generatedShield = prev.shield;
        if (shieldMultiplier > 0) {
           generatedShield += Math.floor(prev.maxHp * 0.10 + prev.defense * shieldMultiplier);
        }
        return { ...prev, cooldowns: nextCooldowns, shield: generatedShield };
      });

      if (dmgMultiplier > 0) {
        const dmg = calculateDamage(attacker.attack, defender.defense, dmgMultiplier);

        setDefender((prev: any) => {
           let remainingDmg = dmg;
           let newShield = prev.shield;
           if (newShield > 0) {
             if (newShield >= remainingDmg) {
               newShield -= remainingDmg;
               remainingDmg = 0;
             } else {
               remainingDmg -= newShield;
               newShield = 0;
             }
           }
           const newHp = Math.max(0, prev.currentHp - remainingDmg);
           return { ...prev, shield: newShield, currentHp: newHp };
        });

        addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
      } else {
        addLog(`${attacker.name} uses [${skill.name}], guarding intensely!`);
      }

      setTimeout(() => {
        if (isPlayer) {
          setEnemyCard(curr => {
            if (curr!.currentHp <= 0) {
              handleWin();
            } else {
              setTurn('ENEMY');
              setTimeout(() => enemyAI(curr!), 1000);
            }
            return curr;
          });
        } else {
          setPlayerCard(curr => {
            if (curr!.currentHp <= 0) {
              handleLose();
            } else {
              setIsAnimating(false);
              setTurn('PLAYER');
            }
            return curr;
          });
        }
      }, 500);

    }, 500); 
  };

  const enemyAI = (currentEnemy: Combatant) => {
     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = playerCard!.currentHp + playerCard!.shield;

     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!;

     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, playerCard!.defense, 1.8);
     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     else if (playerCard!.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handleWin = () => {
    setPhase('RESULT');
    setIsAnimating(false);
    const expGain = 250;
    const creditGain = 500;

    setPlayerState(prev => {
      let newExp = prev.exp + expGain;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + creditGain,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const HealthBar = ({ current, max, shield, name }: { current: number, max: number, shield: number, name: string }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2">{name}</span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        {shield > 0 && (
          <div className="text-xs text-blue-300 mt-1 font-bold flex items-center gap-1">
            đź›ˇď¸Ź {shield} Shield
          </div>
        )}
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={playerCard!.currentHp} max={playerCard!.maxHp} shield={playerCard!.shield} name={playerCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             <Card card={playerCard!} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={enemyCard!.currentHp} max={enemyCard!.maxHp} shield={enemyCard!.shield} name={enemyCard!.name} />
          <div className={`transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             <Card card={enemyCard!} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-50 pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard!.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-24 flex flex-col items-center justify-center ${btnStyle} relative group`}
                    title={skill.description}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70 bg-black/30 px-2 rounded mt-1">{skill.type}</span>

                    {/* Tooltip Description on hover */}
                    <div className="absolute -top-12 left-1/2 transform -translate-x-1/2 bg-black text-white text-xs p-2 rounded w-48 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-lg border border-gray-600">
                      {skill.description}
                    </div>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-3xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-50">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-6 uppercase tracking-widest ${playerCard!.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard!.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               {playerCard!.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Rewards</h3>
                   <div className="text-white text-lg font-bold text-green-400 mb-1">+500 Credits</div>
                   <div className="text-white text-lg font-bold text-blue-400">+250 EXP</div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>REBATTLE (Same Card)</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType, SkillType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [loadingBanner, setLoadingBanner] = useState(true);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = async () => {
      setLoadingBanner(true);
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          if (parsed.date === today) {
            setBanner(parsed);
            setLoadingBanner(false);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      const newBanner = await fetchDailyBanner();
      if (newBanner) {
        setBanner(newBanner);
        localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
      } else {
        const fallbackImageUrl1 = await getRandomAnimeImage('CrimsonDemon');
        const fallbackImageUrl2 = await getRandomAnimeImage('AquaPaladin');
        const fallback: BannerData = {
          date: today,
          featuredCards: [
            { 
              name: "Lucky Chloe", rarity: Rarity.UR, element: ElementType.FIRE, description: "A fiery demon from the abyss.", hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: fallbackImageUrl1,
              skills: [
                { type: SkillType.BASIC, name: "Cinder Strike", description: "Deals standard fire damage." },
                { type: SkillType.HEAVY, name: "Abyssal Burst", description: "Deals heavy fire damage. (2-turn CD)" },
                { type: SkillType.DEFEND, name: "Demon Aegis", description: "Raises a fiery shield. (2-turn CD)" },
                { type: SkillType.ULTIMATE, name: "Lucky Annihilation", description: "Devastating ultimate attack. (4-turn CD)" }
              ]
            },
            { 
              name: "Jean Devus", rarity: Rarity.SSR, element: ElementType.WATER, description: "Defender of the deep seas.", hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: fallbackImageUrl2,
              skills: [
                { type: SkillType.BASIC, name: "Tidal Slash", description: "Deals standard water damage." },
                { type: SkillType.HEAVY, name: "Leviathan Crush", description: "Deals heavy water damage. (2-turn CD)" },
                { type: SkillType.DEFEND, name: "Oceanic Barrier", description: "Raises a water shield. (2-turn CD)" },
                { type: SkillType.ULTIMATE, name: "Devus Tsunami", description: "Devastating ultimate water attack. (4-turn CD)" }
              ]
            }
          ]
        };
        setBanner(fallback);
      }
      setLoadingBanner(false);
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];
    const elementsToGenerate: ElementType[] = [];

    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0;
      } else if (times === 10 && i === 9) {
        forceSR = true;
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0;
      }
      baseCards.push(card);

      // If it's a generic card missing a name, push its element to the generator queue
      if (!card.name && card.element) {
        elementsToGenerate.push(card.element);
      }
    }

    // Fetch unique profiles (Names + Skills) for generic cards
    const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
    let profileIdx = 0;

    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c) => {
        if (c.name) {
           // It's a banner card that already has name and skills
           return c as CardData;
        }

        const profile = uniqueProfiles[profileIdx++];
        const finalName = profile?.name || `Warrior ${profileIdx}`;
        const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType);
        const imageUrl = await getRandomAnimeImage(finalName + c.id);

        return { ...c, name: finalName, skills: finalSkills, imageUrl } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

