import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity, SkillType, Skill } from '../types';
import { getRandomAnimeImage } from '../utils/animeImageApi';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateProceduralName = () => {
  const titles = ["Vanguard", "Ronin", "Striker", "Warlord", "Phantom", "Oracle", "Behemoth", "Tempest", "Wraith", "Paladin"];
  const prefixes = ["Crimson", "Mecha", "Void", "Astral", "Savage", "Divine", "Cyber", "Abyssal", "Iron", "Storm"];
  const randomSuffix = Math.floor(Math.random() * 999);
  return `${prefixes[Math.floor(Math.random() * prefixes.length)]}-${titles[Math.floor(Math.random() * titles.length)]} v${randomSuffix}`;
};

export const generateProceduralSkills = (element: ElementType): Skill[] => {
  const elementalPrefixes: Record<ElementType, string[]> = {
    [ElementType.FIRE]: ["Crimson", "Inferno", "Blaze", "Scorching", "Ember"],
    [ElementType.WATER]: ["Aqua", "Tidal", "Frost", "Abyssal", "Crystal"],
    [ElementType.EARTH]: ["Terra", "Gaia", "Quake", "Stone", "Iron"],
    [ElementType.LIGHT]: ["Radiant", "Holy", "Lumina", "Aegis", "Divine"],
    [ElementType.DARK]: ["Shadow", "Void", "Abyss", "Phantom", "Doom"]
  };
  const pre = elementalPrefixes[element];
  const p = () => pre[Math.floor(Math.random() * pre.length)];

  return [
    { type: SkillType.BASIC, name: `${p()} Strike`, description: "Deals standard elemental damage to the target." },
    { type: SkillType.HEAVY, name: `${p()} Buster`, description: "A powerful blow dealing 1.8x damage. (2-turn CD)" },
    { type: SkillType.DEFEND, name: `${p()} Guard`, description: "Raises a massive shield block based on max HP. (2-turn CD)" },
    { type: SkillType.ULTIMATE, name: `Absolute ${p()} Nova`, description: "Devastating ultimate attack dealing 2.5x damage. (4-turn CD)" }
  ];
};

export interface CardProfile {
  name: string;
  description: string;
  skills: Skill[];
}

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;

  const ai = new GoogleGenAI({ apiKey });
  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Give them highly unique, cool, and action-packed names (e.g. "Crimson Vanguard", "Mecha-Ronin 77", "Vortex Striker"). Do not use generic names.
    Provide a short, epic character summary/lore description.
    Also provide 4 distinct skill names for each fitting their element, along with a short description of what the skill does mechanically.
    Provide realistic RPG stats based on rarity (UR: ~15000 HP, ~850 ATK, ~450 DEF. SSR: ~6000 HP, ~350 ATK, ~200 DEF).
  `;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                rarity: { type: Type.STRING },
                element: { type: Type.STRING },
                description: { type: Type.STRING },
                hp: { type: Type.INTEGER },
                attack: { type: Type.INTEGER },
                defense: { type: Type.INTEGER },
                skillBasicName: { type: Type.STRING },
                skillBasicDesc: { type: Type.STRING },
                skillHeavyName: { type: Type.STRING },
                skillHeavyDesc: { type: Type.STRING },
                skillDefendName: { type: Type.STRING },
                skillDefendDesc: { type: Type.STRING },
                skillUltimateName: { type: Type.STRING },
                skillUltimateDesc: { type: Type.STRING }
              },
              required: ["name", "rarity", "element", "description", "hp", "attack", "defense", "skillBasicName", "skillBasicDesc", "skillHeavyName", "skillHeavyDesc", "skillDefendName", "skillDefendDesc", "skillUltimateName", "skillUltimateDesc"]
            }
          }
        }
      });

      if (response.text) {
        try {
          const parsed = JSON.parse(response.text);
          const featuredCards = await Promise.all(parsed.map(async (c: any) => {
            const el = Object.values(ElementType).includes(c.element) ? c.element as ElementType : ElementType.LIGHT;
            return {
              name: c.name,
              rarity: c.rarity as Rarity,
              element: el,
              description: c.description,
              hp: c.hp,
              maxHp: c.hp,
              attack: c.attack,
              defense: c.defense,
              imageUrl: await getRandomAnimeImage(c.name),
              skills: [
                { type: SkillType.BASIC, name: c.skillBasicName, description: c.skillBasicDesc },
                { type: SkillType.HEAVY, name: c.skillHeavyName, description: c.skillHeavyDesc },
                { type: SkillType.DEFEND, name: c.skillDefendName, description: c.skillDefendDesc },
                { type: SkillType.ULTIMATE, name: c.skillUltimateName, description: c.skillUltimateDesc }
              ]
            };
          }));
          return { date: today, featuredCards };
        } catch (e) {
           console.warn("Parse error", e);
        }
      }
    } catch (error: any) {
      if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }
  return null;
};

export const generateCardProfiles = async (count: number, elements: ElementType[]): Promise<CardProfile[]> => {
  const apiKey = process.env.API_KEY;

  const fallbackProfiles = elements.map(el => ({
    name: generateProceduralName(),
    description: `A mysterious warrior of the ${el} element, forged in battles unknown.`,
    skills: generateProceduralSkills(el)
  }));

  if (!apiKey) return fallbackProfiles;

  const ai = new GoogleGenAI({ apiKey });
  const elementsStr = elements.join(', ');
  const prompt = `Generate exactly ${count} unique anime character profiles matching these elements in order: [${elementsStr}]. 
  For each character:
  1. Provide a highly unique, cool, and action-packed specific name (e.g., 'Crimson Vanguard', 'Mecha-Ronin 77', 'Vortex Striker'). Avoid generic names.
  2. Provide a short, epic character summary/lore description.
  3. Provide 4 epic and uniquely named combat skills that match their element: 1 basic attack, 1 heavy attack, 1 defensive move, and 1 ultimate move.
  4. Include a short description for what each skill does.`;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                basicAttackName: { type: Type.STRING },
                basicAttackDesc: { type: Type.STRING },
                heavyAttackName: { type: Type.STRING },
                heavyAttackDesc: { type: Type.STRING },
                defensiveSkillName: { type: Type.STRING },
                defensiveSkillDesc: { type: Type.STRING },
                ultimateSkillName: { type: Type.STRING },
                ultimateSkillDesc: { type: Type.STRING }
              },
              required: ["name", "description", "basicAttackName", "basicAttackDesc", "heavyAttackName", "heavyAttackDesc", "defensiveSkillName", "defensiveSkillDesc", "ultimateSkillName", "ultimateSkillDesc"]
            }
          }
        }
      });

      if (response.text) {
         try {
           const profiles = JSON.parse(response.text);
           if (Array.isArray(profiles) && profiles.length >= count) {
              return profiles.slice(0, count).map((p: any) => ({
                name: p.name,
                description: p.description,
                skills: [
                  { type: SkillType.BASIC, name: p.basicAttackName, description: p.basicAttackDesc },
                  { type: SkillType.HEAVY, name: p.heavyAttackName, description: p.heavyAttackDesc },
                  { type: SkillType.DEFEND, name: p.defensiveSkillName, description: p.defensiveSkillDesc },
                  { type: SkillType.ULTIMATE, name: p.ultimateSkillName, description: p.ultimateSkillDesc }
                ]
              }));
           }
         } catch(e) {
           console.warn("Failed to parse profile json", e);
         }
      }
    } catch (error: any) {
       if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }

  return fallbackProfiles;
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills, generateProceduralName } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [loadingBanner, setLoadingBanner] = useState(true);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = async () => {
      setLoadingBanner(true);
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          if (parsed.date === today) {
            setBanner(parsed);
            setLoadingBanner(false);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      const newBanner = await fetchDailyBanner();
      if (newBanner) {
        setBanner(newBanner);
        localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
      } else {
        const fallbackName1 = generateProceduralName();
        const fallbackName2 = generateProceduralName();
        const fallbackImageUrl1 = await getRandomAnimeImage(fallbackName1);
        const fallbackImageUrl2 = await getRandomAnimeImage(fallbackName2);

        const fallback: BannerData = {
          date: today,
          featuredCards: [
            { 
              name: fallbackName1, rarity: Rarity.UR, element: ElementType.FIRE, description: "A fiery legend summoned from the abyss.", hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: fallbackImageUrl1,
              skills: generateProceduralSkills(ElementType.FIRE)
            },
            { 
              name: fallbackName2, rarity: Rarity.SSR, element: ElementType.WATER, description: "A staunch defender of the deep seas.", hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: fallbackImageUrl2,
              skills: generateProceduralSkills(ElementType.WATER)
            }
          ]
        };
        setBanner(fallback);
      }
      setLoadingBanner(false);
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];
    const elementsToGenerate: ElementType[] = [];

    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0;
      } else if (times === 10 && i === 9) {
        forceSR = true;
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0;
      }
      baseCards.push(card);

      // If it's a generic card missing a name, push its element to the generator queue
      if (!card.name && card.element) {
        elementsToGenerate.push(card.element);
      }
    }

    // Fetch unique profiles (Names + Skills) for generic cards
    const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
    let profileIdx = 0;

    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c) => {
        if (c.name) {
           // It's a banner card that already has name and skills
           return c as CardData;
        }

        const profile = uniqueProfiles[profileIdx++];
        const finalName = profile?.name || `Warrior ${profileIdx}`;
        const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType);
        const imageUrl = await getRandomAnimeImage(finalName + c.id);

        return { ...c, name: finalName, skills: finalSkills, imageUrl } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto">

        {loadingBanner ? (
           <div className="text-2xl text-white animate-pulse">Communicating with AI to generate daily banner...</div>
        ) : !pullResults ? (
          <>
            {banner && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex flex-col items-center gap-6 mt-auto">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.3s_forwards]" />
                </div>
              ))}
            </div>
            <Button className="mt-12" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.5s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn">
             <div className="flex flex-col items-center">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity, SkillType, Skill } from '../types';
import { getRandomAnimeImage } from '../utils/animeImageApi';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateProceduralName = () => {
  const titles = ["Vanguard", "Ronin", "Striker", "Warlord", "Phantom", "Oracle", "Behemoth", "Tempest", "Wraith", "Paladin"];
  const prefixes = ["Crimson", "Mecha", "Void", "Astral", "Savage", "Divine", "Cyber", "Abyssal", "Iron", "Storm"];
  const randomSuffix = Math.floor(Math.random() * 999);
  return `${prefixes[Math.floor(Math.random() * prefixes.length)]}-${titles[Math.floor(Math.random() * titles.length)]} v${randomSuffix}`;
};

export const generateProceduralDescription = (element: ElementType, name: string): string => {
  const templates = [
    `A legendary ${element} warrior known for unmatched prowess on the battlefield.`,
    `Hailing from the hidden ${element} realms, ${name} strikes fear into the hearts of enemies.`,
    `Armed with the ancient power of ${element}, this combatant bows to no one.`,
    `A wandering soul infused with ${element} energy, seeking the ultimate challenge.`,
    `Stories speak of a ${element} entity that single-handedly turned the tide of the Great War. That entity is ${name}.`,
    `Forged in the deepest parts of the ${element} domain, ${name} is an unstoppable force of nature.`,
    `Once a mere mortal, now a vessel of pure ${element} destruction.`
  ];
  return templates[Math.floor(Math.random() * templates.length)];
};

export const generateProceduralSkills = (element: ElementType): Skill[] => {
  const elementalPrefixes: Record<ElementType, string[]> = {
    [ElementType.FIRE]: ["Crimson", "Inferno", "Blaze", "Scorching", "Ember"],
    [ElementType.WATER]: ["Aqua", "Tidal", "Frost", "Abyssal", "Crystal"],
    [ElementType.EARTH]: ["Terra", "Gaia", "Quake", "Stone", "Iron"],
    [ElementType.LIGHT]: ["Radiant", "Holy", "Lumina", "Aegis", "Divine"],
    [ElementType.DARK]: ["Shadow", "Void", "Abyss", "Phantom", "Doom"]
  };
  const pre = elementalPrefixes[element];
  const p = () => pre[Math.floor(Math.random() * pre.length)];

  return [
    { type: SkillType.BASIC, name: `${p()} Strike`, description: "Deals standard elemental damage to the target." },
    { type: SkillType.HEAVY, name: `${p()} Buster`, description: "A powerful blow dealing 1.8x damage. (2-turn CD)" },
    { type: SkillType.DEFEND, name: `${p()} Guard`, description: "Raises a massive shield block based on max HP. (2-turn CD)" },
    { type: SkillType.ULTIMATE, name: `Absolute ${p()} Nova`, description: "Devastating ultimate attack dealing 2.5x damage. (4-turn CD)" }
  ];
};

export interface CardProfile {
  name: string;
  description: string;
  skills: Skill[];
}

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;

  const ai = new GoogleGenAI({ apiKey });
  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Give them highly unique, cool, and action-packed names (e.g. "Crimson Vanguard", "Mecha-Ronin 77", "Vortex Striker"). Do not use generic names.
    Provide a short, epic, and highly distinct character summary/lore description. Do not repeat lore. Make each completely unique.
    Also provide 4 distinct skill names for each fitting their element, along with a short description of what the skill does mechanically.
    Provide realistic RPG stats based on rarity (UR: ~15000 HP, ~850 ATK, ~450 DEF. SSR: ~6000 HP, ~350 ATK, ~200 DEF).
  `;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                rarity: { type: Type.STRING },
                element: { type: Type.STRING },
                description: { type: Type.STRING },
                hp: { type: Type.INTEGER },
                attack: { type: Type.INTEGER },
                defense: { type: Type.INTEGER },
                skillBasicName: { type: Type.STRING },
                skillBasicDesc: { type: Type.STRING },
                skillHeavyName: { type: Type.STRING },
                skillHeavyDesc: { type: Type.STRING },
                skillDefendName: { type: Type.STRING },
                skillDefendDesc: { type: Type.STRING },
                skillUltimateName: { type: Type.STRING },
                skillUltimateDesc: { type: Type.STRING }
              },
              required: ["name", "rarity", "element", "description", "hp", "attack", "defense", "skillBasicName", "skillBasicDesc", "skillHeavyName", "skillHeavyDesc", "skillDefendName", "skillDefendDesc", "skillUltimateName", "skillUltimateDesc"]
            }
          }
        }
      });

      if (response.text) {
        try {
          const parsed = JSON.parse(response.text);
          const featuredCards = await Promise.all(parsed.map(async (c: any) => {
            const el = Object.values(ElementType).includes(c.element) ? c.element as ElementType : ElementType.LIGHT;
            return {
              name: c.name,
              rarity: c.rarity as Rarity,
              element: el,
              description: c.description,
              hp: c.hp,
              maxHp: c.hp,
              attack: c.attack,
              defense: c.defense,
              imageUrl: await getRandomAnimeImage(c.name),
              skills: [
                { type: SkillType.BASIC, name: c.skillBasicName, description: c.skillBasicDesc },
                { type: SkillType.HEAVY, name: c.skillHeavyName, description: c.skillHeavyDesc },
                { type: SkillType.DEFEND, name: c.skillDefendName, description: c.skillDefendDesc },
                { type: SkillType.ULTIMATE, name: c.skillUltimateName, description: c.skillUltimateDesc }
              ]
            };
          }));
          return { date: today, featuredCards };
        } catch (e) {
           console.warn("Parse error", e);
        }
      }
    } catch (error: any) {
      if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }
  return null;
};

export const generateCardProfiles = async (count: number, elements: ElementType[]): Promise<CardProfile[]> => {
  const apiKey = process.env.API_KEY;

  const fallbackProfiles = elements.map(el => {
    const name = generateProceduralName();
    return {
      name,
      description: generateProceduralDescription(el, name),
      skills: generateProceduralSkills(el)
    };
  });

  if (!apiKey) return fallbackProfiles;

  const ai = new GoogleGenAI({ apiKey });
  const elementsStr = elements.join(', ');
  const prompt = `Generate exactly ${count} unique anime character profiles matching these elements in order: [${elementsStr}]. 
  For each character:
  1. Provide a highly unique, cool, and action-packed specific name (e.g., 'Crimson Vanguard', 'Mecha-Ronin 77', 'Vortex Striker'). Avoid generic names.
  2. Provide a short, epic character summary/lore description. Make each description extremely unique, completely different from one another.
  3. Provide 4 epic and uniquely named combat skills that match their element: 1 basic attack, 1 heavy attack, 1 defensive move, and 1 ultimate move.
  4. Include a short description for what each skill does.`;

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                basicAttackName: { type: Type.STRING },
                basicAttackDesc: { type: Type.STRING },
                heavyAttackName: { type: Type.STRING },
                heavyAttackDesc: { type: Type.STRING },
                defensiveSkillName: { type: Type.STRING },
                defensiveSkillDesc: { type: Type.STRING },
                ultimateSkillName: { type: Type.STRING },
                ultimateSkillDesc: { type: Type.STRING }
              },
              required: ["name", "description", "basicAttackName", "basicAttackDesc", "heavyAttackName", "heavyAttackDesc", "defensiveSkillName", "defensiveSkillDesc", "ultimateSkillName", "ultimateSkillDesc"]
            }
          }
        }
      });

      if (response.text) {
         try {
           const profiles = JSON.parse(response.text);
           if (Array.isArray(profiles) && profiles.length >= count) {
              return profiles.slice(0, count).map((p: any) => ({
                name: p.name,
                description: p.description,
                skills: [
                  { type: SkillType.BASIC, name: p.basicAttackName, description: p.basicAttackDesc },
                  { type: SkillType.HEAVY, name: p.heavyAttackName, description: p.heavyAttackDesc },
                  { type: SkillType.DEFEND, name: p.defensiveSkillName, description: p.defensiveSkillDesc },
                  { type: SkillType.ULTIMATE, name: p.ultimateSkillName, description: p.ultimateSkillDesc }
                ]
              }));
           }
         } catch(e) {
           console.warn("Failed to parse profile json", e);
         }
      }
    } catch (error: any) {
       if (attempt < 3) await sleep(Math.pow(2, attempt) * 1000);
    }
  }

  return fallbackProfiles;
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills, generateProceduralName, generateProceduralDescription } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [loadingBanner, setLoadingBanner] = useState(true);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = async () => {
      setLoadingBanner(true);
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          if (parsed.date === today) {
            setBanner(parsed);
            setLoadingBanner(false);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      const newBanner = await fetchDailyBanner();
      if (newBanner) {
        setBanner(newBanner);
        localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
      } else {
        const fallbackName1 = generateProceduralName();
        const fallbackName2 = generateProceduralName();
        const fallbackImageUrl1 = await getRandomAnimeImage(fallbackName1);
        const fallbackImageUrl2 = await getRandomAnimeImage(fallbackName2);

        const fallback: BannerData = {
          date: today,
          featuredCards: [
            { 
              name: fallbackName1, rarity: Rarity.UR, element: ElementType.FIRE, description: generateProceduralDescription(ElementType.FIRE, fallbackName1), hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: fallbackImageUrl1,
              skills: generateProceduralSkills(ElementType.FIRE)
            },
            { 
              name: fallbackName2, rarity: Rarity.SSR, element: ElementType.WATER, description: generateProceduralDescription(ElementType.WATER, fallbackName2), hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: fallbackImageUrl2,
              skills: generateProceduralSkills(ElementType.WATER)
            }
          ]
        };
        setBanner(fallback);
      }
      setLoadingBanner(false);
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];
    const elementsToGenerate: ElementType[] = [];

    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0;
      } else if (times === 10 && i === 9) {
        forceSR = true;
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0;
      }
      baseCards.push(card);

      // If it's a generic card missing a name, push its element to the generator queue
      if (!card.name && card.element) {
        elementsToGenerate.push(card.element);
      }
    }

    // Fetch unique profiles (Names + Descriptions + Skills) for generic cards
    const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
    let profileIdx = 0;

    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c) => {
        if (c.name) {
           // It's a banner card that already has name, description, and skills
           return c as CardData;
        }

        const profile = uniqueProfiles[profileIdx++];
        const finalName = profile?.name || generateProceduralName();
        const finalDescription = profile?.description || generateProceduralDescription(c.element as ElementType, finalName);
        const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType);
        const imageUrl = await getRandomAnimeImage(finalName + c.id);

        return { 
          ...c, 
          name: finalName, 
          description: finalDescription, 
          skills: finalSkills, 
          imageUrl 
        } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto">

        {loadingBanner ? (
           <div className="text-2xl text-white animate-pulse">Communicating with AI to generate daily banner...</div>
        ) : !pullResults ? (
          <>
            {banner && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex flex-col items-center gap-6 mt-auto">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.3s_forwards]" />
                </div>
              ))}
            </div>
            <Button className="mt-12" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.5s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn">
             <div className="flex flex-col items-center">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { AppScreen, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { Button } from '../components/ui/Button';
import { RARITY_STATS } from '../constants';
import { fetchAnimeWallpaper } from '../utils/animeImageApi';
import { generateProceduralSkills, generateCardProfiles, generateProceduralDescription } from '../services/geminiService';

interface DeckScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const DeckScreen: React.FC<DeckScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [filter, setFilter] = useState<Rarity | 'ALL'>('ALL');
  const [selectedCard, setSelectedCard] = useState<CardData | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);

    const reader = new FileReader();
    reader.onload = async (event) => {
      const result = event.target?.result as string;

      const elements = Object.values(ElementType);
      const element = elements[Math.floor(Math.random() * elements.length)];
      const stats = RARITY_STATS[Rarity.UR];

      // Automatically contact AI to fetch highly unique profile for the imported custom card
      const profiles = await generateCardProfiles(1, [element]);
      const profile = profiles[0];
      const fallbackName = `Custom ${file.name.split('.')[0].substring(0, 10)}`;

      const newCard: CardData = {
        id: `custom_${Date.now()}`,
        name: profile?.name || fallbackName,
        rarity: Rarity.UR,
        element: element,
        imageUrl: result,
        hp: stats.hp,
        maxHp: stats.hp,
        attack: stats.atk,
        defense: stats.def,
        description: profile?.description || generateProceduralDescription(element, profile?.name || fallbackName),
        isCustom: true,
        skills: profile?.skills || generateProceduralSkills(element)
      };

      setPlayerState(prev => ({
        ...prev,
        inventory: [newCard, ...prev.inventory]
      }));

      setIsImporting(false);
    };
    reader.readAsDataURL(file);
  };

  const filteredInventory = playerState.inventory.filter(c => filter === 'ALL' || c.rarity === filter);

  const rarityValues = { [Rarity.UR]: 5, [Rarity.SSR]: 4, [Rarity.SR]: 3, [Rarity.R]: 2, [Rarity.N]: 1 };
  filteredInventory.sort((a, b) => {
    if (rarityValues[b.rarity] !== rarityValues[a.rarity]) {
      return rarityValues[b.rarity] - rarityValues[a.rarity];
    }
    return b.id.localeCompare(a.id);
