import React, { useState, useCallback, useRef } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity, Skill, SkillType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS, BATTLE_REWARDS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';
import { generateCardProfiles, generateProceduralSkills } from '../services/geminiService';
import { fetchAttackEffect } from '../utils/effectApi';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
  cooldowns: Record<SkillType, number>;
}

interface FloatingText {
  id: number;
  text: string;
  target: 'PLAYER' | 'ENEMY';
  color: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');

  // Visual FX States
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);
  const [activeEffect, setActiveEffect] = useState<{ target: 'PLAYER' | 'ENEMY', url: string } | null>(null);
  const [floatingTexts, setFloatingTexts] = useState<FloatingText[]>([]);
  const [earnedRewards, setEarnedRewards] = useState({ credits: 0, exp: 0 });

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element, card.name) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 10), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element, name);

    const imageUrl = await getRandomAnimeImage(name + Date.now());
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated!"]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const addFloatingText = (text: string, target: 'PLAYER' | 'ENEMY', color: string) => {
    const id = Date.now() + Math.random();
    setFloatingTexts(prev => [...prev, { id, text, target, color }]);
    setTimeout(() => {
      setFloatingTexts(prev => prev.filter(t => t.id !== id));
    }, 1000);
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; 
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = async (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    if (!playerCard || !enemyCard) return;

    setIsAnimating(true);

    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCard : enemyCard;
    const defender = isPlayer ? enemyCard : playerCard;
    const targetSide = isPlayer ? 'ENEMY' : 'PLAYER';

    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;

    switch (skill.type) {
      case SkillType.BASIC: dmgMultiplier = 1.0; break;
      case SkillType.HEAVY: dmgMultiplier = 1.8; newCooldown = 2; break;
      case SkillType.DEFEND: dmgMultiplier = 0; shieldMultiplier = 1.5; newCooldown = 2; break;
      case SkillType.ULTIMATE: dmgMultiplier = 2.5; shieldMultiplier = 1.0; newCooldown = 4; break;
    }

    // 1. Dash Forward Animation Time
    await sleep(250); 

    // 2. Fetch and Play Impact/Magic Effect
    const effectBaseUrl = await fetchAttackEffect(skill.type);
    setActiveEffect({ target: targetSide, url: `${effectBaseUrl}?t=${Date.now()}` });

    // 3. Pre-calculate damage to use in logs and floating text synchronously
    let dmg = 0;
    if (dmgMultiplier > 0) {
      dmg = calculateDamage(attacker.attack, defender.defense, dmgMultiplier);
      addFloatingText(dmg.toString(), targetSide, 'text-red-500');
      addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
    } else {
      addFloatingText('GUARD', actor, 'text-blue-400');
      addLog(`${attacker.name} uses [${skill.name}], guarding intensely!`);
    }

    // 4. Apply State Mutations
    const setAttacker = isPlayer ? setPlayerCard : setEnemyCard;
    const setDefender = isPlayer ? setEnemyCard : setPlayerCard;

    setAttacker((prev: Combatant | null) => {
      if (!prev) return null;
      const nextCooldowns = { ...prev.cooldowns };
      (Object.keys(nextCooldowns) as SkillType[]).forEach(k => {
          if (nextCooldowns[k] > 0) nextCooldowns[k] -= 1;
      });
      nextCooldowns[skill.type] = newCooldown;

      let generatedShield = prev.shield;
      if (shieldMultiplier > 0) {
          generatedShield += Math.floor(prev.maxHp * 0.10 + prev.defense * shieldMultiplier);
      }
      return { ...prev, cooldowns: nextCooldowns, shield: generatedShield };
    });

    if (dmg > 0) {
      setDefender((prev: Combatant | null) => {
        if (!prev) return null;
        let remainingDmg = dmg;
        let newShield = prev.shield;
        if (newShield > 0) {
          if (newShield >= remainingDmg) {
            newShield -= remainingDmg;
            remainingDmg = 0;
          } else {
            remainingDmg -= newShield;
            newShield = 0;
          }
        }
        const newHp = Math.max(0, prev.currentHp - remainingDmg);
        return { ...prev, shield: newShield, currentHp: newHp };
      });
    }

    // 5. Wait for effect animation to finish playing
    await sleep(600);
    setActiveEffect(null);

    // 6. Attacker Returns Time
    await sleep(250); 
    setIsAnimating(false);

    // 7. Check Win/Loss & Next Turn logic
    // We fetch latest HP using functional updates or evaluating current state post-calculation
    const defenderHpRemaining = defender.currentHp - dmg; 

    if (defenderHpRemaining <= 0) {
       if (isPlayer) {
          handleWin(enemyCard); 
       } else {
          handleLose();
       }
    } else {
       if (isPlayer) {
         setTurn('ENEMY');
         // Pass updated enemy HP into the AI evaluation accurately via a slight delay
         setTimeout(() => {
           setEnemyCard(currEnemy => {
              if(currEnemy) enemyAI(currEnemy);
              return currEnemy;
           });
         }, 800);
       } else {
         setTurn('PLAYER');
       }
    }
  };

  const enemyAI = (currentEnemy: Combatant) => {
     if (!playerCard) return;

     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = playerCard.currentHp + playerCard.shield;

     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!;

     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, playerCard.defense, 1.8);

     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     else if (playerCard.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const handleWin = (defeatedEnemy: Combatant) => {
    setPhase('RESULT');
    setIsAnimating(false);

    const baseRewards = BATTLE_REWARDS[defeatedEnemy.rarity];
    const variance = (Math.random() * 0.2) + 0.9; 
    const finalExp = Math.floor(baseRewards.exp * variance);
    const finalCredits = Math.floor(baseRewards.credits * variance);

    setEarnedRewards({ exp: finalExp, credits: finalCredits });

    setPlayerState(prev => {
      let newExp = prev.exp + finalExp;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + finalCredits,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const HealthBar = ({ current, max, shield, name }: { current: number, max: number, shield: number, name: string }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2">{name}</span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        {shield > 0 && (
          <div className="text-xs text-blue-300 mt-1 font-bold flex items-center gap-1">
            đź›ˇď¸Ź {shield} Shield
          </div>
        )}
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition cursor-pointer">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        {/* Player Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={playerCard!.currentHp} max={playerCard!.maxHp} shield={playerCard!.shield} name={playerCard!.name} />

          <div className={`relative transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             <Card card={playerCard!} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'PLAYER' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'PLAYER').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        {/* Enemy Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar current={enemyCard!.currentHp} max={enemyCard!.maxHp} shield={enemyCard!.shield} name={enemyCard!.name} />

          <div className={`relative transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             <Card card={enemyCard!} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'ENEMY' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'ENEMY').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-[60] pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard!.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-24 flex flex-col items-center justify-center ${btnStyle} relative group`}
                    title={skill.description}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70 bg-black/30 px-2 rounded mt-1">{skill.type}</span>

                    {/* Tooltip Description on hover */}
                    <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 bg-black text-white text-xs p-2 rounded w-64 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-lg border border-gray-600 text-center">
                      {skill.description}
                    </div>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-3xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-[100]">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-2 uppercase tracking-widest ${playerCard!.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard!.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               <p className="text-gray-400 mb-6 uppercase text-sm font-bold">
                 {playerCard!.currentHp > 0 ? `Defeated ${enemyCard!.rarity} Boss` : `Lost to ${enemyCard!.rarity} Boss`}
               </p>

               {playerCard!.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Earned Rewards</h3>
                   <div className="flex justify-between items-center mb-1">
                     <span className="text-white">Credits:</span>
                     <span className="text-green-400 font-black text-xl">+{earnedRewards.credits}</span>
                   </div>
                   <div className="flex justify-between items-center">
                     <span className="text-white">Experience:</span>
                     <span className="text-blue-400 font-black text-xl">+{earnedRewards.exp}</span>
                   </div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>REBATTLE (Same Card)</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes floatUpFade {
          0% { transform: translate(-50%, -50%) scale(1.5); opacity: 1; filter: blur(0px); }
          100% { transform: translate(-50%, -150%) scale(1); opacity: 0; filter: blur(2px); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity, Skill, SkillType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS, BATTLE_REWARDS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';
import { generateCardProfiles, generateProceduralSkills } from '../services/geminiService';
import { fetchAttackEffect } from '../utils/effectApi';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
  isGuarding: boolean;
  cooldowns: Record<SkillType, number>;
}

interface FloatingText {
  id: number;
  text: string;
  target: 'PLAYER' | 'ENEMY';
  color: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');

  // Refs for resolving stale closures in async timeout loops
  const playerCardRef = useRef<Combatant | null>(null);
  const enemyCardRef = useRef<Combatant | null>(null);

  // Visual FX States
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);
  const [activeEffect, setActiveEffect] = useState<{ target: 'PLAYER' | 'ENEMY', url: string } | null>(null);
  const [floatingTexts, setFloatingTexts] = useState<FloatingText[]>([]);
  const [earnedRewards, setEarnedRewards] = useState({ credits: 0, exp: 0 });

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  useEffect(() => {
    playerCardRef.current = playerCard;
    enemyCardRef.current = enemyCard;
  }, [playerCard, enemyCard]);

  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element, card.name) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 10), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element, name);

    const imageUrl = await getRandomAnimeImage(name + Date.now());
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      isGuarding: false,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      isGuarding: false,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated! Elements dictate advantage."]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const getElementalMultiplier = (atkEl: ElementType, defEl: ElementType) => {
    if (atkEl === ElementType.WATER && defEl === ElementType.FIRE) return 1.5;
    if (atkEl === ElementType.FIRE && defEl === ElementType.EARTH) return 1.5;
    if (atkEl === ElementType.EARTH && defEl === ElementType.WATER) return 1.5;
    if (atkEl === ElementType.LIGHT && defEl === ElementType.DARK) return 1.5;
    if (atkEl === ElementType.DARK && defEl === ElementType.LIGHT) return 1.5;

    if (atkEl === ElementType.FIRE && defEl === ElementType.WATER) return 0.75;
    if (atkEl === ElementType.EARTH && defEl === ElementType.FIRE) return 0.75;
    if (atkEl === ElementType.WATER && defEl === ElementType.EARTH) return 0.75;
    if (atkEl === defEl) return 0.9;

    return 1.0;
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const addFloatingText = (text: string, target: 'PLAYER' | 'ENEMY', color: string) => {
    const id = Date.now() + Math.random();
    setFloatingTexts(prev => [...prev, { id, text, target, color }]);
    setTimeout(() => {
      setFloatingTexts(prev => prev.filter(t => t.id !== id));
    }, 1000);
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; 
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = async (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCardRef.current : enemyCardRef.current;
    const defender = isPlayer ? enemyCardRef.current : playerCardRef.current;

    if (!attacker || !defender) return;

    setIsAnimating(true);
    const targetSide = isPlayer ? 'ENEMY' : 'PLAYER';

    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;
    let isGuardingAction = false;

    switch (skill.type) {
      case SkillType.BASIC: dmgMultiplier = 1.0; break;
      case SkillType.HEAVY: dmgMultiplier = 1.8; newCooldown = 2; break;
      case SkillType.DEFEND: dmgMultiplier = 0; shieldMultiplier = 1.5; newCooldown = 2; isGuardingAction = true; break;
      case SkillType.ULTIMATE: dmgMultiplier = 2.5; shieldMultiplier = 1.0; newCooldown = 4; break;
    }

    // 1. Dash Forward Animation Time
    await sleep(250); 

    // 2. Fetch and Play Impact/Magic Effect
    const effectBaseUrl = await fetchAttackEffect(skill.type);
    setActiveEffect({ target: targetSide, url: `${effectBaseUrl}?t=${Date.now()}` });

    // 3. Pre-calculate damage with Defense + Element Systems
    const elementMult = getElementalMultiplier(attacker.element, defender.element);
    const isTargetGuarding = defender.isGuarding;
    const finalDmgMultiplier = dmgMultiplier * elementMult * (isTargetGuarding ? 0.5 : 1);

    let dmg = 0;
    if (dmgMultiplier > 0) {
      dmg = calculateDamage(attacker.attack, defender.defense, finalDmgMultiplier);

      let textParams = { text: dmg.toString(), color: 'text-red-500' };
      if (isTargetGuarding) textParams = { text: `${dmg} (GUARDED)`, color: 'text-blue-300' };
      else if (elementMult > 1) textParams = { text: `${dmg} (WEAK!)`, color: 'text-yellow-400' };
      else if (elementMult < 1) textParams = { text: `${dmg} (RESIST)`, color: 'text-gray-400' };

      addFloatingText(textParams.text, targetSide, textParams.color);
      addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
    } else {
      addFloatingText('GUARD UP', actor, 'text-blue-400');
      addLog(`${attacker.name} enters a defensive stance!`);
    }

    // Properly calculate exact remaining HP to prevent ghost-shield bugs
    let actualDmgToHp = dmg;
    if (defender.shield >= dmg) {
      actualDmgToHp = 0;
    } else {
      actualDmgToHp = dmg - defender.shield;
    }
    const defenderHpRemaining = defender.currentHp - actualDmgToHp;

    // 4. Apply State Mutations
    const setAttacker = isPlayer ? setPlayerCard : setEnemyCard;
    const setDefender = isPlayer ? setEnemyCard : setPlayerCard;

    setAttacker((prev: Combatant | null) => {
      if (!prev) return null;
      const nextCooldowns = { ...prev.cooldowns };
      (Object.keys(nextCooldowns) as SkillType[]).forEach(k => {
          if (nextCooldowns[k] > 0) nextCooldowns[k] -= 1;
      });
      nextCooldowns[skill.type] = newCooldown;

      let generatedShield = prev.shield;
      if (shieldMultiplier > 0) {
          generatedShield += Math.floor(prev.maxHp * 0.10 + prev.defense * shieldMultiplier);
      }
      return { ...prev, cooldowns: nextCooldowns, shield: generatedShield, isGuarding: isGuardingAction };
    });

    if (dmg > 0) {
      setDefender((prev: Combatant | null) => {
        if (!prev) return null;
        let remainingDmg = dmg;
        let newShield = prev.shield;
        if (newShield > 0) {
          if (newShield >= remainingDmg) {
            newShield -= remainingDmg;
            remainingDmg = 0;
          } else {
            remainingDmg -= newShield;
            newShield = 0;
          }
        }
        const newHp = Math.max(0, prev.currentHp - remainingDmg);
        return { ...prev, shield: newShield, currentHp: newHp };
      });
    }

    // 5. Wait for effect animation to finish playing
    await sleep(600);
    setActiveEffect(null);

    // 6. Attacker Returns Time
    await sleep(250); 
    setIsAnimating(false);

    // 7. Check Win/Loss & Next Turn logic safely
    if (defenderHpRemaining <= 0) {
       if (isPlayer) {
          handleWin(enemyCardRef.current!); 
       } else {
          handleLose();
       }
    } else {
       if (isPlayer) {
         setTurn('ENEMY');
         setTimeout(() => enemyAI(), 800);
       } else {
         setTurn('PLAYER');
       }
    }
  };

  const enemyAI = () => {
     const currentPlayer = playerCardRef.current;
     const currentEnemy = enemyCardRef.current;
     if (!currentPlayer || !currentEnemy) return;

     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = currentPlayer.currentHp + currentPlayer.shield;

     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!;

     // Factor in Defense System & Element Advantage into AI logic
     const elementMult = getElementalMultiplier(currentEnemy.element, currentPlayer.element);
     const guardMult = currentPlayer.isGuarding ? 0.5 : 1;
     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, currentPlayer.defense, 1.8 * elementMult * guardMult);

     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     else if (currentPlayer.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const handleWin = (defeatedEnemy: Combatant) => {
    setPhase('RESULT');
    setIsAnimating(false);

    const baseRewards = BATTLE_REWARDS[defeatedEnemy.rarity];
    const variance = (Math.random() * 0.2) + 0.9; 
    const finalExp = Math.floor(baseRewards.exp * variance);
    const finalCredits = Math.floor(baseRewards.credits * variance);

    setEarnedRewards({ exp: finalExp, credits: finalCredits });

    setPlayerState(prev => {
      let newExp = prev.exp + finalExp;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + finalCredits,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const HealthBar = ({ current, max, shield, isGuarding, name, element }: { current: number, max: number, shield: number, isGuarding: boolean, name: string, element: ElementType }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2 flex items-center gap-1">
            <span className="bg-slate-700 px-1 rounded text-[10px] tracking-widest">{element}</span> {name}
          </span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        <div className="flex justify-between mt-1 h-4">
          {shield > 0 ? (
            <div className="text-xs text-blue-300 font-bold flex items-center gap-1">
              đź›ˇď¸Ź {shield}
            </div>
          ) : <div></div>}
          {isGuarding && (
            <div className="text-xs text-purple-300 font-bold flex items-center gap-1 animate-pulse">
              âš”ď¸Ź GUARDING
            </div>
          )}
        </div>
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition cursor-pointer">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        {/* Player Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={playerCard?.currentHp || 0} 
            max={playerCard?.maxHp || 1} 
            shield={playerCard?.shield || 0} 
            isGuarding={playerCard?.isGuarding || false}
            name={playerCard?.name || 'Player'} 
            element={playerCard?.element || ElementType.LIGHT}
          />

          <div className={`relative transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             {playerCard && <Card card={playerCard} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />}

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'PLAYER' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'PLAYER').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        {/* Enemy Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={enemyCard?.currentHp || 0} 
            max={enemyCard?.maxHp || 1} 
            shield={enemyCard?.shield || 0} 
            isGuarding={enemyCard?.isGuarding || false}
            name={enemyCard?.name || 'Enemy'} 
            element={enemyCard?.element || ElementType.DARK}
          />

          <div className={`relative transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             {enemyCard && <Card card={enemyCard} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />}

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'ENEMY' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'ENEMY').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-[60] pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && playerCard && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-24 flex flex-col items-center justify-center ${btnStyle} relative group`}
                    title={skill.description}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70 bg-black/30 px-2 rounded mt-1">{skill.type}</span>

                    {/* Tooltip Description on hover */}
                    <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 bg-black text-white text-xs p-2 rounded w-64 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-lg border border-gray-600 text-center">
                      {skill.description}
                    </div>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-3xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && playerCard && enemyCard && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-[100]">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-2 uppercase tracking-widest ${playerCard.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               <p className="text-gray-400 mb-6 uppercase text-sm font-bold">
                 {playerCard.currentHp > 0 ? `Defeated ${enemyCard.rarity} Boss` : `Lost to ${enemyCard.rarity} Boss`}
               </p>

               {playerCard.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Earned Rewards</h3>
                   <div className="flex justify-between items-center mb-1">
                     <span className="text-white">Credits:</span>
                     <span className="text-green-400 font-black text-xl">+{earnedRewards.credits}</span>
                   </div>
                   <div className="flex justify-between items-center">
                     <span className="text-white">Experience:</span>
                     <span className="text-blue-400 font-black text-xl">+{earnedRewards.exp}</span>
                   </div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>REBATTLE (Same Card)</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes floatUpFade {
          0% { transform: translate(-50%, -50%) scale(1.5); opacity: 1; filter: blur(0px); }
          100% { transform: translate(-50%, -150%) scale(1); opacity: 0; filter: blur(2px); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { AppScreen, CardData, ElementType, PlayerState, Rarity, Skill, SkillType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { BattleStage } from '../components/BattleStage';
import { RARITY_STATS, BATTLE_REWARDS } from '../constants';
import { Button } from '../components/ui/Button';
import { getRandomAnimeImage } from '../utils/animeImageApi';
import { generateCardProfiles, generateProceduralSkills } from '../services/geminiService';
import { fetchAttackEffect } from '../utils/effectApi';

interface BattleScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

type BattlePhase = 'SELECT' | 'FIGHT' | 'RESULT';

interface Combatant extends CardData {
  currentHp: number;
  shield: number;
  isGuarding: boolean;
  cooldowns: Record<SkillType, number>;
}

interface FloatingText {
  id: number;
  text: string;
  target: 'PLAYER' | 'ENEMY';
  color: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');

  // Refs for resolving stale closures in async timeout loops
  const playerCardRef = useRef<Combatant | null>(null);
  const enemyCardRef = useRef<Combatant | null>(null);

  // Visual FX States
  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);
  const [activeEffect, setActiveEffect] = useState<{ target: 'PLAYER' | 'ENEMY', url: string } | null>(null);
  const [floatingTexts, setFloatingTexts] = useState<FloatingText[]>([]);
  const [earnedRewards, setEarnedRewards] = useState({ credits: 0, exp: 0 });

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  useEffect(() => {
    playerCardRef.current = playerCard;
    enemyCardRef.current = enemyCard;
  }, [playerCard, enemyCard]);

  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element, card.name) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 10), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element, name);

    const imageUrl = await getRandomAnimeImage(name + Date.now());
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      isGuarding: false,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    setIsAnimating(true);

    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      isGuarding: false,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated! Elements dictate advantage."]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
      setIsAnimating(false);
    }, 2000);
  };

  const getElementalMultiplier = (atkEl: ElementType, defEl: ElementType) => {
    if (atkEl === ElementType.WATER && defEl === ElementType.FIRE) return 1.5;
    if (atkEl === ElementType.FIRE && defEl === ElementType.EARTH) return 1.5;
    if (atkEl === ElementType.EARTH && defEl === ElementType.WATER) return 1.5;
    if (atkEl === ElementType.LIGHT && defEl === ElementType.DARK) return 1.5;
    if (atkEl === ElementType.DARK && defEl === ElementType.LIGHT) return 1.5;

    if (atkEl === ElementType.FIRE && defEl === ElementType.WATER) return 0.75;
    if (atkEl === ElementType.EARTH && defEl === ElementType.FIRE) return 0.75;
    if (atkEl === ElementType.WATER && defEl === ElementType.EARTH) return 0.75;
    if (atkEl === defEl) return 0.9;

    return 1.0;
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const addFloatingText = (text: string, target: 'PLAYER' | 'ENEMY', color: string) => {
    const id = Date.now() + Math.random();
    setFloatingTexts(prev => [...prev, { id, text, target, color }]);
    setTimeout(() => {
      setFloatingTexts(prev => prev.filter(t => t.id !== id));
    }, 1000);
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; 
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = async (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCardRef.current : enemyCardRef.current;
    const defender = isPlayer ? enemyCardRef.current : playerCardRef.current;

    if (!attacker || !defender) return;

    setIsAnimating(true);
    const targetSide = isPlayer ? 'ENEMY' : 'PLAYER';

    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;
    let isGuardingAction = false;

    switch (skill.type) {
      case SkillType.BASIC: dmgMultiplier = 1.0; break;
      case SkillType.HEAVY: dmgMultiplier = 1.8; newCooldown = 2; break;
      case SkillType.DEFEND: dmgMultiplier = 0; shieldMultiplier = 1.5; newCooldown = 2; isGuardingAction = true; break;
      case SkillType.ULTIMATE: dmgMultiplier = 2.5; shieldMultiplier = 1.0; newCooldown = 4; break;
    }

    // 1. Dash Forward Animation Time
    await sleep(250); 

    // 2. Fetch and Play Impact/Magic Effect
    const effectBaseUrl = await fetchAttackEffect(skill.type);
    setActiveEffect({ target: targetSide, url: `${effectBaseUrl}?t=${Date.now()}` });

    // 3. Pre-calculate damage with Defense + Element Systems
    const elementMult = getElementalMultiplier(attacker.element, defender.element);
    const isTargetGuarding = defender.isGuarding;
    const finalDmgMultiplier = dmgMultiplier * elementMult * (isTargetGuarding ? 0.5 : 1);

    let dmg = 0;
    if (dmgMultiplier > 0) {
      dmg = calculateDamage(attacker.attack, defender.defense, finalDmgMultiplier);

      let textParams = { text: dmg.toString(), color: 'text-red-500' };
      if (isTargetGuarding) textParams = { text: `${dmg} (GUARDED)`, color: 'text-blue-300' };
      else if (elementMult > 1) textParams = { text: `${dmg} (WEAK!)`, color: 'text-yellow-400' };
      else if (elementMult < 1) textParams = { text: `${dmg} (RESIST)`, color: 'text-gray-400' };

      addFloatingText(textParams.text, targetSide, textParams.color);
      addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
    } else {
      addFloatingText('GUARD UP', actor, 'text-blue-400');
      addLog(`${attacker.name} enters a defensive stance!`);
    }

    // 4. Calculate exact state synchronously to prevent ghost shields or missed damage
    const nextAttackerCooldowns = { ...attacker.cooldowns };
    (Object.keys(nextAttackerCooldowns) as SkillType[]).forEach(k => {
        if (nextAttackerCooldowns[k] > 0) nextAttackerCooldowns[k] -= 1;
    });
    nextAttackerCooldowns[skill.type] = newCooldown;

    let newAttackerShield = attacker.shield;
    if (shieldMultiplier > 0) {
        newAttackerShield += Math.floor(attacker.maxHp * 0.10 + attacker.defense * shieldMultiplier);
    }

    const newAttacker = {
      ...attacker,
      cooldowns: nextAttackerCooldowns,
      shield: newAttackerShield,
      isGuarding: isGuardingAction
    };

    let newDefenderShield = defender.shield;
    let remainingDmg = dmg;

    if (newDefenderShield > 0 && remainingDmg > 0) {
      if (newDefenderShield >= remainingDmg) {
        newDefenderShield -= remainingDmg;
        remainingDmg = 0;
      } else {
        remainingDmg -= newDefenderShield;
        newDefenderShield = 0;
      }
    }

    const newDefenderHp = Math.max(0, defender.currentHp - remainingDmg);

    const newDefender = {
      ...defender,
      shield: newDefenderShield,
      currentHp: newDefenderHp
    };

    // 5. Apply states
    if (isPlayer) {
      setPlayerCard(newAttacker);
      setEnemyCard(newDefender);
    } else {
      setEnemyCard(newAttacker);
      setPlayerCard(newDefender);
    }

    // 6. Wait for effect animation to finish playing
    await sleep(600);
    setActiveEffect(null);

    // 7. Attacker Returns Time
    await sleep(250); 
    setIsAnimating(false);

    // 8. Check Win/Loss & Next Turn logic
    if (newDefenderHp <= 0) {
       if (isPlayer) {
          handleWin(newDefender); 
       } else {
          handleLose();
       }
    } else {
       if (isPlayer) {
         setTurn('ENEMY');
         setTimeout(() => enemyAI(), 800);
       } else {
         setTurn('PLAYER');
       }
    }
  };

  const enemyAI = () => {
     const currentPlayer = playerCardRef.current;
     const currentEnemy = enemyCardRef.current;
     if (!currentPlayer || !currentEnemy) return;

     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = currentPlayer.currentHp + currentPlayer.shield;

     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!;

     // Factor in Defense System & Element Advantage into AI logic
     const elementMult = getElementalMultiplier(currentEnemy.element, currentPlayer.element);
     const guardMult = currentPlayer.isGuarding ? 0.5 : 1;
     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, currentPlayer.defense, 1.8 * elementMult * guardMult);

     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     else if (currentPlayer.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const handleWin = (defeatedEnemy: Combatant) => {
    setPhase('RESULT');
    setIsAnimating(false);

    const baseRewards = BATTLE_REWARDS[defeatedEnemy.rarity];
    const variance = (Math.random() * 0.2) + 0.9; 
    const finalExp = Math.floor(baseRewards.exp * variance);
    const finalCredits = Math.floor(baseRewards.credits * variance);

    setEarnedRewards({ exp: finalExp, credits: finalCredits });

    setPlayerState(prev => {
      let newExp = prev.exp + finalExp;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + finalCredits,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const HealthBar = ({ current, max, shield, isGuarding, name, element }: { current: number, max: number, shield: number, isGuarding: boolean, name: string, element: ElementType }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2 flex items-center gap-1">
            <span className="bg-slate-700 px-1 rounded text-[10px] tracking-widest">{element}</span> {name}
          </span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        <div className="flex justify-between mt-1 h-4">
          {shield > 0 ? (
            <div className="text-xs text-blue-300 font-bold flex items-center gap-1">
              đź›ˇď¸Ź {shield}
            </div>
          ) : <div></div>}
          {isGuarding && (
            <div className="text-xs text-purple-300 font-bold flex items-center gap-1 animate-pulse">
              âš”ď¸Ź GUARDING
            </div>
          )}
        </div>
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />

        {isAnimating && (
          <div className="absolute inset-0 bg-black/60 z-50 flex items-center justify-center backdrop-blur-sm">
             <div className="text-2xl font-black text-white tracking-widest uppercase animate-pulse">Summoning Enemy...</div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition cursor-pointer">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        {/* Player Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={playerCard?.currentHp || 0} 
            max={playerCard?.maxHp || 1} 
            shield={playerCard?.shield || 0} 
            isGuarding={playerCard?.isGuarding || false}
            name={playerCard?.name || 'Player'} 
            element={playerCard?.element || ElementType.LIGHT}
          />

          <div className={`relative transform-gpu ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.5s_ease-in-out]' : ''}`}>
             {playerCard && <Card card={playerCard} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />}

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'PLAYER' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'PLAYER').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all ${vsFlashing ? 'animate-[flashVS_2s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        {/* Enemy Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-300 ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={enemyCard?.currentHp || 0} 
            max={enemyCard?.maxHp || 1} 
            shield={enemyCard?.shield || 0} 
            isGuarding={enemyCard?.isGuarding || false}
            name={enemyCard?.name || 'Enemy'} 
            element={enemyCard?.element || ElementType.DARK}
          />

          <div className={`relative transform-gpu ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.5s_ease-in-out]' : ''}`}>
             {enemyCard && <Card card={enemyCard} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />}

             {/* Visual VFX Overlay */}
             {activeEffect?.target === 'ENEMY' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl" />
             )}

             {/* Floating Text */}
             {floatingTexts.filter(t => t.target === 'ENEMY').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_1s_ease-out_forwards] ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-[60] pointer-events-none flex flex-col justify-between">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && playerCard && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.5s_ease-out]">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-24 flex flex-col items-center justify-center ${btnStyle} relative group`}
                    title={skill.description}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70 bg-black/30 px-2 rounded mt-1">{skill.type}</span>

                    {/* Tooltip Description on hover */}
                    <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 bg-black text-white text-xs p-2 rounded w-64 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-lg border border-gray-600 text-center">
                      {skill.description}
                    </div>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-3xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && playerCard && enemyCard && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-[100]">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.3s_ease-out]">
               <h2 className={`text-5xl font-black mb-2 uppercase tracking-widest ${playerCard.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               <p className="text-gray-400 mb-6 uppercase text-sm font-bold">
                 {playerCard.currentHp > 0 ? `Defeated ${enemyCard.rarity} Boss` : `Lost to ${enemyCard.rarity} Boss`}
               </p>

               {playerCard.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Earned Rewards</h3>
                   <div className="flex justify-between items-center mb-1">
                     <span className="text-white">Credits:</span>
                     <span className="text-green-400 font-black text-xl">+{earnedRewards.credits}</span>
                   </div>
                   <div className="flex justify-between items-center">
                     <span className="text-white">Experience:</span>
                     <span className="text-blue-400 font-black text-xl">+{earnedRewards.exp}</span>
                   </div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 <Button onClick={() => startGame(playerCard!)}>NEXT BATTLE</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes floatUpFade {
          0% { transform: translate(-50%, -50%) scale(1.5); opacity: 1; filter: blur(0px); }
          100% { transform: translate(-50%, -150%) scale(1); opacity: 0; filter: blur(2px); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

