  color: string;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const BattleScreen: React.FC<BattleScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [phase, setPhase] = useState<BattlePhase>('SELECT');
  const [playerCard, setPlayerCard] = useState<Combatant | null>(null);
  const [enemyCard, setEnemyCard] = useState<Combatant | null>(null);
  const [combatLog, setCombatLog] = useState<string[]>([]);
  const [turn, setTurn] = useState<'PLAYER' | 'ENEMY'>('PLAYER');

  const playerCardRef = useRef<Combatant | null>(null);
  const enemyCardRef = useRef<Combatant | null>(null);

  const [isAnimating, setIsAnimating] = useState(false);
  const [vsFlashing, setVsFlashing] = useState(false);
  const [activeEffect, setActiveEffect] = useState<{ target: 'PLAYER' | 'ENEMY', url: string } | null>(null);
  const [floatingTexts, setFloatingTexts] = useState<FloatingText[]>([]);
  const [earnedRewards, setEarnedRewards] = useState({ credits: 0, exp: 0 });

  const [victoryImageUrl, setVictoryImageUrl] = useState<string | null>(null);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  const themes = ['forest', 'volcano', 'ice', 'space'] as const;
  const [stageTheme] = useState(themes[Math.floor(Math.random() * themes.length)]);

  useEffect(() => {
    playerCardRef.current = playerCard;
    enemyCardRef.current = enemyCard;
  }, [playerCard, enemyCard]);

  useEffect(() => {
    if (phase === 'SELECT') {
      setVictoryImageUrl(null);
      setShowShareModal(false);
    }
  }, [phase]);

  const ensureSkills = (card: CardData): CardData => {
    if (card.skills && card.skills.length === 4) return card;
    return { ...card, skills: generateProceduralSkills(card.element, card.name) };
  };

  const generateEnemyAsync = useCallback(async (): Promise<Combatant> => {
    const rarities = [Rarity.N, Rarity.R, Rarity.SR, Rarity.SSR, Rarity.UR];
    const rollIndex = Math.min(Math.floor(Math.random() * 3) + Math.floor(playerState.level / 10), 4);
    const rarity = rarities[rollIndex];

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rarity];

    // Instant generation utilizing background object pool
    const generatedProfiles = await generateCardProfiles(1, [element]);
    const profile = generatedProfiles[0];
    const name = profile?.name || `Rogue ${rarity} Entity`;
    const skills = profile?.skills || generateProceduralSkills(element, name);

    const imageUrl = await getRandomAnimeImage(name + Date.now());
    const bossHp = Math.floor(stats.hp * 1.5);

    return {
      id: `enemy_${Date.now()}`,
      name,
      rarity,
      element,
      imageUrl,
      hp: bossHp,
      maxHp: bossHp,
      currentHp: bossHp,
      attack: stats.atk,
      defense: stats.def,
      shield: 0,
      isGuarding: false,
      skills,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    };
  }, [playerState.level]);

  const startGame = async (selectedCard: CardData) => {
    // Instant battle setup, no artificial blocking!
    const enemy = await generateEnemyAsync();
    const readyCard = ensureSkills(selectedCard);

    setPlayerCard({ 
      ...readyCard, 
      currentHp: readyCard.hp, 
      shield: 0,
      isGuarding: false,
      cooldowns: { [SkillType.BASIC]: 0, [SkillType.HEAVY]: 0, [SkillType.DEFEND]: 0, [SkillType.ULTIMATE]: 0 }
    });
    setEnemyCard(enemy);
    setCombatLog(["Battle Initiated! Elements dictate advantage."]);
    setPhase('FIGHT');
    setTurn('PLAYER');

    setVsFlashing(true);
    setTimeout(() => {
      setVsFlashing(false);
    }, 800); // reduced flash duration for snappier experience
  };

  const getElementalMultiplier = (atkEl: ElementType, defEl: ElementType) => {
    if (atkEl === ElementType.WATER && defEl === ElementType.FIRE) return 1.5;
    if (atkEl === ElementType.FIRE && defEl === ElementType.EARTH) return 1.5;
    if (atkEl === ElementType.EARTH && defEl === ElementType.WATER) return 1.5;
    if (atkEl === ElementType.LIGHT && defEl === ElementType.DARK) return 1.5;
    if (atkEl === ElementType.DARK && defEl === ElementType.LIGHT) return 1.5;

    if (atkEl === ElementType.FIRE && defEl === ElementType.WATER) return 0.75;
    if (atkEl === ElementType.EARTH && defEl === ElementType.FIRE) return 0.75;
    if (atkEl === ElementType.WATER && defEl === ElementType.EARTH) return 0.75;
    if (atkEl === defEl) return 0.9;
    return 1.0;
  };

  const calculateDamage = (atk: number, def: number, multiplier: number) => {
    const baseDamage = ((atk * multiplier) * (atk * multiplier)) / ((atk * multiplier) + def * 1.5);
    const variance = (Math.random() * 0.3) + 0.85; 
    return Math.max(1, Math.floor(baseDamage * variance));
  };

  const addFloatingText = (text: string, target: 'PLAYER' | 'ENEMY', color: string) => {
    const id = Date.now() + Math.random();
    setFloatingTexts(prev => [...prev, { id, text, target, color }]);
    setTimeout(() => {
      setFloatingTexts(prev => prev.filter(t => t.id !== id));
    }, 800);
  };

  const addLog = (msg: string) => {
    setCombatLog(prev => [msg, ...prev].slice(0, 5));
  };

  const handlePlayerSkill = (skill: Skill) => {
    if (!playerCard || !enemyCard || turn !== 'PLAYER' || isAnimating) return;
    if (playerCard.cooldowns[skill.type] > 0) return; 
    executeTurn(skill, 'PLAYER');
  };

  const executeTurn = async (skill: Skill, actor: 'PLAYER' | 'ENEMY') => {
    const isPlayer = actor === 'PLAYER';
    const attacker = isPlayer ? playerCardRef.current : enemyCardRef.current;
    const defender = isPlayer ? enemyCardRef.current : playerCardRef.current;

    if (!attacker || !defender) return;

    setIsAnimating(true);
    const targetSide = isPlayer ? 'ENEMY' : 'PLAYER';

    let dmgMultiplier = 1.0;
    let shieldMultiplier = 0;
    let newCooldown = 0;
    let isGuardingAction = false;

    switch (skill.type) {
      case SkillType.BASIC: dmgMultiplier = 1.0; break;
      case SkillType.HEAVY: dmgMultiplier = 1.8; newCooldown = 2; break;
      case SkillType.DEFEND: dmgMultiplier = 0; shieldMultiplier = 1.5; newCooldown = 2; isGuardingAction = true; break;
      case SkillType.ULTIMATE: dmgMultiplier = 2.5; shieldMultiplier = 1.0; newCooldown = 4; break;
    }

    await sleep(50); // Instant dash animation

    const effectBaseUrl = await fetchAttackEffect(skill.type);
    setActiveEffect({ target: targetSide, url: `${effectBaseUrl}?t=${Date.now()}` });

    const elementMult = getElementalMultiplier(attacker.element, defender.element);
    const isTargetGuarding = defender.isGuarding;
    const finalDmgMultiplier = dmgMultiplier * elementMult * (isTargetGuarding ? 0.5 : 1);

    let dmg = 0;
    if (dmgMultiplier > 0) {
      dmg = calculateDamage(attacker.attack, defender.defense, finalDmgMultiplier);

      let textParams = { text: dmg.toString(), color: 'text-red-500' };
      if (isTargetGuarding) textParams = { text: `${dmg} (GUARDED)`, color: 'text-blue-300' };
      else if (elementMult > 1) textParams = { text: `${dmg} (WEAK!)`, color: 'text-yellow-400' };
      else if (elementMult < 1) textParams = { text: `${dmg} (RESIST)`, color: 'text-gray-400' };

      addFloatingText(textParams.text, targetSide, textParams.color);
      addLog(`${attacker.name} uses [${skill.name}] for ${dmg} damage!`);
    } else {
      addFloatingText('GUARD UP', actor, 'text-blue-400');
      addLog(`${attacker.name} enters a defensive stance!`);
    }

    const nextAttackerCooldowns = { ...attacker.cooldowns };
    (Object.keys(nextAttackerCooldowns) as SkillType[]).forEach(k => {
        if (nextAttackerCooldowns[k] > 0) nextAttackerCooldowns[k] -= 1;
    });
    nextAttackerCooldowns[skill.type] = newCooldown;

    let newAttackerShield = attacker.shield;
    if (shieldMultiplier > 0) {
        newAttackerShield += Math.floor(attacker.maxHp * 0.10 + attacker.defense * shieldMultiplier);
    }

    const newAttacker = {
      ...attacker,
      cooldowns: nextAttackerCooldowns,
      shield: newAttackerShield,
      isGuarding: isGuardingAction
    };

    let newDefenderShield = defender.shield;
    let remainingDmg = dmg;

    if (newDefenderShield > 0 && remainingDmg > 0) {
      if (newDefenderShield >= remainingDmg) {
        newDefenderShield -= remainingDmg;
        remainingDmg = 0;
      } else {
        remainingDmg -= newDefenderShield;
        newDefenderShield = 0;
      }
    }

    const newDefenderHp = Math.max(0, defender.currentHp - remainingDmg);

    const newDefender = {
      ...defender,
      shield: newDefenderShield,
      currentHp: newDefenderHp
    };

    if (isPlayer) {
      setPlayerCard(newAttacker);
      setEnemyCard(newDefender);
    } else {
      setEnemyCard(newAttacker);
      setPlayerCard(newDefender);
    }

    await sleep(300); // Extremely fast effect resolution
    setActiveEffect(null);
    await sleep(50); // Fast attacker return
    setIsAnimating(false);

    if (newDefenderHp <= 0) {
       if (isPlayer) {
          handleWin(newDefender); 
       } else {
          handleLose();
       }
    } else {
       if (isPlayer) {
         setTurn('ENEMY');
         setTimeout(() => enemyAI(), 300); // CPU fast response
       } else {
         setTurn('PLAYER');
       }
    }
  };

  const enemyAI = () => {
     const currentPlayer = playerCardRef.current;
     const currentEnemy = enemyCardRef.current;
     if (!currentPlayer || !currentEnemy) return;

     const hpPercent = currentEnemy.currentHp / currentEnemy.maxHp;
     const playerEffectiveHp = currentPlayer.currentHp + currentPlayer.shield;

     const availableSkills = currentEnemy.skills!.filter(s => currentEnemy.cooldowns[s.type] === 0);
     const getSkill = (t: SkillType) => availableSkills.find(s => s.type === t);

     let chosenSkill = getSkill(SkillType.BASIC)!;

     const elementMult = getElementalMultiplier(currentEnemy.element, currentPlayer.element);
     const guardMult = currentPlayer.isGuarding ? 0.5 : 1;
     const estimatedHeavyDmg = calculateDamage(currentEnemy.attack, currentPlayer.defense, 1.8 * elementMult * guardMult);

     if (getSkill(SkillType.HEAVY) && estimatedHeavyDmg >= playerEffectiveHp) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     } 
     else if (getSkill(SkillType.ULTIMATE) && Math.random() > 0.2) {
        chosenSkill = getSkill(SkillType.ULTIMATE)!;
     }
     else if (hpPercent < 0.3 && currentEnemy.shield === 0 && getSkill(SkillType.DEFEND)) {
        chosenSkill = getSkill(SkillType.DEFEND)!;
     }
     else if (currentPlayer.shield > currentEnemy.attack && getSkill(SkillType.HEAVY)) {
        chosenSkill = getSkill(SkillType.HEAVY)!;
     }
     else {
        chosenSkill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
     }

     executeTurn(chosenSkill, 'ENEMY');
  };

  const handleWin = (defeatedEnemy: Combatant) => {
    setPhase('RESULT');
    setIsAnimating(false);

    const baseRewards = BATTLE_REWARDS[defeatedEnemy.rarity];
    const variance = (Math.random() * 0.2) + 0.9; 
    const finalExp = Math.floor(baseRewards.exp * variance);
    const finalCredits = Math.floor(baseRewards.credits * variance);

    setEarnedRewards({ exp: finalExp, credits: finalCredits });

    setPlayerState(prev => {
      let newExp = prev.exp + finalExp;
      let newLevel = prev.level;
      if (newExp >= 1000) {
        newLevel += Math.floor(newExp / 1000);
        newExp = newExp % 1000;
      }
      return {
        ...prev,
        credits: prev.credits + finalCredits,
        exp: newExp,
        level: newLevel
      };
    });
  };

  const handleLose = () => {
    setPhase('RESULT');
    setIsAnimating(false);
  };

  const handleGenerateShareImage = async () => {
    if (victoryImageUrl) {
      setShowShareModal(true);
      return;
    }

    if (!playerCard) return;

    setIsGeneratingImage(true);
    const url = await generateVictoryImage(playerCard.name, playerCard.element, playerCard.currentHp);
    if (url) {
      setVictoryImageUrl(url);
      setShowShareModal(true);
    } else {
      alert("Failed to generate victory image from AI. Please try again.");
    }
    setIsGeneratingImage(false);
  };

  const handleShare = async () => {
    if (!victoryImageUrl || !playerCard) return;
    if (navigator.share) {
      try {
        const res = await fetch(victoryImageUrl);
        const blob = await res.blob();
        const file = new File([blob], 'victory.png', { type: 'image/png' });
        await navigator.share({
          title: 'Epic Anime Gacha Battle Victory',
          text: `I just won a battle using ${playerCard.name} with ${playerCard.currentHp} HP remaining!`,
          files: [file]
        });
      } catch (err) {
        console.error("Error sharing:", err);
      }
    } else {
       const a = document.createElement('a');
       a.href = victoryImageUrl;
       a.download = `victory_${playerCard.name.replace(/\s+/g, '_')}.png`;
       a.click();
    }
  };

  const HealthBar = ({ current, max, shield, isGuarding, name, element }: { current: number, max: number, shield: number, isGuarding: boolean, name: string, element: ElementType }) => {
    const hpPercent = Math.max(0, (current / max) * 100);
    return (
      <div className="w-64 bg-black/80 p-2 rounded border border-white/20 backdrop-blur-sm shadow-xl transform-gpu will-change-transform">
        <div className="flex justify-between text-xs font-bold mb-1">
          <span className="truncate pr-2 flex items-center gap-1">
            <span className="bg-slate-700 px-1 rounded text-[10px] tracking-widest">{element}</span> {name}
          </span>
          <span className="shrink-0">{current} / {max}</span>
        </div>
        <div className="relative h-4 bg-gray-800 rounded overflow-hidden transform-gpu">
          <div className={`absolute top-0 left-0 h-full transition-all duration-300 transform-gpu ${hpPercent > 50 ? 'bg-green-500' : hpPercent > 20 ? 'bg-yellow-500' : 'bg-red-500'}`} style={{ width: `${hpPercent}%` }}></div>
        </div>
        <div className="flex justify-between mt-1 h-4">
          {shield > 0 ? (
            <div className="text-xs text-blue-300 font-bold flex items-center gap-1">
              đź›ˇď¸Ź {shield}
            </div>
          ) : <div></div>}
          {isGuarding && (
            <div className="text-xs text-purple-300 font-bold flex items-center gap-1 animate-pulse transform-gpu">
              âš”ď¸Ź GUARDING
            </div>
          )}
        </div>
      </div>
    );
  };

  if (phase === 'SELECT') {
    return (
      <div className="relative w-full h-full bg-slate-900 flex flex-col">
        <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SELECT FIGHTER" />
        <div className="flex-1 overflow-y-auto pt-24 px-8 pb-8 transform-gpu will-change-transform">
           {playerState.inventory.length === 0 ? (
             <div className="text-center mt-20">
               <h2 className="text-2xl mb-4">You have no cards!</h2>
               <Button onClick={() => changeScreen(AppScreen.GACHA)}>Go to Summon</Button>
             </div>
           ) : (
             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
                {playerState.inventory.map(card => (
                  <div key={card.id} onClick={() => startGame(card)} className="transform hover:scale-105 transition cursor-pointer transform-gpu">
                    <Card card={ensureSkills(card)} size="sm" />
                  </div>
                ))}
             </div>
           )}
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <BattleStage theme={stageTheme}>

        {/* Player Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-200 transform-gpu will-change-transform ${turn === 'PLAYER' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={playerCard?.currentHp || 0} 
            max={playerCard?.maxHp || 1} 
            shield={playerCard?.shield || 0} 
            isGuarding={playerCard?.isGuarding || false}
            name={playerCard?.name || 'Player'} 
            element={playerCard?.element || ElementType.LIGHT}
          />

          <div className={`relative transform-gpu will-change-transform ${isAnimating && turn === 'PLAYER' ? 'animate-[attackMoveRight_0.2s_ease-in-out]' : ''}`}>
             {playerCard && <Card card={playerCard} size="lg" className="shadow-[20px_20px_30px_rgba(0,0,0,0.8)]" />}

             {activeEffect?.target === 'PLAYER' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl transform-gpu" />
             )}

             {floatingTexts.filter(t => t.target === 'PLAYER').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_0.8s_ease-out_forwards] transform-gpu will-change-transform ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

        <div className={`text-6xl font-black italic mix-blend-overlay pointer-events-none transition-all transform-gpu will-change-transform ${vsFlashing ? 'animate-[flashVS_0.8s_ease-out_forwards] z-50' : 'text-white/50 animate-pulse'}`}>
          VS
        </div>

        {/* Enemy Side */}
        <div className={`flex flex-col items-center gap-4 transition-transform duration-200 transform-gpu will-change-transform ${turn === 'ENEMY' && !isAnimating ? 'scale-110' : 'scale-100 opacity-80'}`}>
          <HealthBar 
            current={enemyCard?.currentHp || 0} 
            max={enemyCard?.maxHp || 1} 
            shield={enemyCard?.shield || 0} 
            isGuarding={enemyCard?.isGuarding || false}
            name={enemyCard?.name || 'Enemy'} 
            element={enemyCard?.element || ElementType.DARK}
          />

          <div className={`relative transform-gpu will-change-transform ${isAnimating && turn === 'ENEMY' ? 'animate-[attackMoveLeft_0.2s_ease-in-out]' : ''}`}>
             {enemyCard && <Card card={enemyCard} size="lg" className="shadow-[-20px_20px_30px_rgba(0,0,0,0.8)] border-red-500" />}

             {activeEffect?.target === 'ENEMY' && (
                <img src={activeEffect.url} alt="Effect" className="absolute inset-0 w-[150%] h-[150%] top-[-25%] left-[-25%] object-contain z-40 pointer-events-none mix-blend-screen drop-shadow-2xl transform-gpu" />
             )}

             {floatingTexts.filter(t => t.target === 'ENEMY').map(t => (
               <div key={t.id} className={`absolute left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-6xl font-black italic drop-shadow-[0_4px_10px_black] z-50 pointer-events-none animate-[floatUpFade_0.8s_ease-out_forwards] transform-gpu will-change-transform ${t.color}`}>
                 {t.text}
               </div>
             ))}
          </div>
        </div>

      </BattleStage>

      <div className="absolute inset-0 z-[60] pointer-events-none flex flex-col justify-between transform-gpu">

        <div className="p-4 flex justify-between">
           <button onClick={() => changeScreen(AppScreen.HOME)} className="pointer-events-auto bg-black/50 text-white px-4 py-2 rounded font-bold hover:bg-black/80 border border-white/20 backdrop-blur-md transform-gpu">FLEE</button>
        </div>

        <div className="absolute top-20 left-1/2 transform -translate-x-1/2 w-[500px] bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 max-h-40 overflow-hidden pointer-events-auto transform-gpu">
          {combatLog.map((log, i) => (
            <div key={i} className={`text-sm ${i === 0 ? 'text-white font-bold text-base' : 'text-gray-400'} opacity-${100 - i*20}`}>{log}</div>
          ))}
        </div>

        {phase === 'FIGHT' && !vsFlashing && playerCard && (
          <div className="p-6 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-auto animate-[fadeIn_0.2s_ease-out] transform-gpu">
            <div className="text-center mb-4 text-white font-black tracking-widest uppercase text-2xl drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
               {turn === 'PLAYER' ? "YOUR TURN" : "ENEMY TURN"}
            </div>

            <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4">
              {playerCard.skills!.map((skill) => {
                const isOnCooldown = playerCard!.cooldowns[skill.type] > 0;

                let btnStyle = "bg-blue-600 hover:bg-blue-500";
                if (skill.type === SkillType.HEAVY) btnStyle = "bg-orange-600 hover:bg-orange-500";
                if (skill.type === SkillType.DEFEND) btnStyle = "bg-green-600 hover:bg-green-500";
                if (skill.type === SkillType.ULTIMATE) btnStyle = "bg-purple-600 hover:bg-purple-500 border-purple-300 shadow-[0_0_15px_rgba(168,85,247,0.8)]";

                return (
                  <Button 
                    key={skill.type}
                    onClick={() => handlePlayerSkill(skill)} 
                    disabled={turn !== 'PLAYER' || isAnimating || isOnCooldown}
                    className={`h-24 flex flex-col items-center justify-center ${btnStyle} relative group transform-gpu`}
                    title={skill.description}
                  >
                    <span className="text-lg uppercase tracking-wide truncate w-full px-2">{skill.name}</span>
                    <span className="text-xs text-white/70 bg-black/30 px-2 rounded mt-1">{skill.type}</span>

                    <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 bg-black text-white text-xs p-2 rounded w-64 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-lg border border-gray-600 text-center transform-gpu">
                      {skill.description}
                    </div>

                    {isOnCooldown && (
                      <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20">
                         <span className="text-red-500 font-black text-3xl">{playerCard!.cooldowns[skill.type]} CD</span>
                      </div>
                    )}
                  </Button>
                )
              })}
            </div>
          </div>
        )}

        {phase === 'RESULT' && playerCard && enemyCard && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-[100] transform-gpu">
             <div className="bg-slate-800 p-8 rounded-2xl border-2 border-slate-600 text-center max-w-md w-full shadow-2xl transform scale-100 animate-[scaleIn_0.2s_ease-out] transform-gpu">
               <h2 className={`text-5xl font-black mb-2 uppercase tracking-widest ${playerCard.currentHp > 0 ? 'text-yellow-400' : 'text-red-500'}`}>
                 {playerCard.currentHp > 0 ? 'VICTORY!' : 'DEFEATED'}
               </h2>

               <p className="text-gray-400 mb-6 uppercase text-sm font-bold">
                 {playerCard.currentHp > 0 ? `Defeated ${enemyCard.rarity} Boss` : `Lost to ${enemyCard.rarity} Boss`}
               </p>

               {playerCard.currentHp > 0 && (
                 <div className="bg-black/50 p-4 rounded mb-6 text-left">
                   <h3 className="text-gray-400 text-sm mb-2 uppercase">Earned Rewards</h3>
                   <div className="flex justify-between items-center mb-1">
                     <span className="text-white">Credits:</span>
                     <span className="text-green-400 font-black text-xl">+{earnedRewards.credits}</span>
                   </div>
                   <div className="flex justify-between items-center">
                     <span className="text-white">Experience:</span>
                     <span className="text-blue-400 font-black text-xl">+{earnedRewards.exp}</span>
                   </div>
                 </div>
               )}

               <div className="flex flex-col gap-3">
                 {playerCard.currentHp > 0 && (
                   <Button variant="gold" onClick={handleGenerateShareImage} disabled={isGeneratingImage}>
                     {isGeneratingImage ? 'GENERATING POSTER...' : 'SHARE VICTORY POSTER'}
                   </Button>
                 )}
                 <Button onClick={() => startGame(playerCard!)}>NEXT BATTLE</Button>
                 <Button variant="secondary" onClick={() => setPhase('SELECT')}>CHANGE FIGHTER</Button>
                 <Button variant="danger" onClick={() => changeScreen(AppScreen.HOME)}>BACK TO HOME</Button>
               </div>
             </div>
          </div>
        )}

        {showShareModal && victoryImageUrl && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 p-4 pointer-events-auto transform-gpu">
            <div className="bg-slate-800 p-6 rounded-2xl border-2 border-yellow-500 max-w-lg w-full flex flex-col items-center shadow-[0_0_50px_rgba(234,179,8,0.5)] transform-gpu">
               <h2 className="text-2xl font-black text-yellow-400 mb-4 tracking-widest text-center">EPIC VICTORY CAPTURED!</h2>
               <img src={victoryImageUrl} alt="Victory" className="w-full h-auto rounded-lg shadow-2xl mb-6 border border-white/20 transform-gpu" />
               <p className="text-gray-300 text-sm mb-6 text-center italic">AI generated via Gemini 2.5 Flash</p>
               <div className="flex gap-4 w-full">
                 <Button className="flex-1" onClick={handleShare}>SHARE / SAVE</Button>
                 <Button variant="secondary" onClick={() => setShowShareModal(false)}>CLOSE</Button>
               </div>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes attackMoveRight {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(50px) scale(1.15) rotate(5deg); }
        }
        @keyframes attackMoveLeft {
          0%, 100% { transform: translateX(0) scale(1.1); }
          50% { transform: translateX(-50px) scale(1.15) rotate(-5deg); }
        }
        @keyframes floatUpFade {
          0% { transform: translate(-50%, -50%) scale(1.5); opacity: 1; filter: blur(0px); }
          100% { transform: translate(-50%, -150%) scale(1); opacity: 0; filter: blur(2px); }
        }
        @keyframes flashVS {
          0% { transform: scale(10) rotate(-10deg); opacity: 0; filter: blur(10px); color: white; }
          15% { transform: scale(0.8) rotate(5deg); opacity: 1; filter: blur(0px); color: red; text-shadow: 0 0 50px red, 0 0 100px yellow; }
          30% { transform: scale(1.2) rotate(-2deg); color: white; text-shadow: 0 0 20px white; }
          100% { transform: scale(1) rotate(0deg); opacity: 1; color: rgba(255,255,255,0.5); text-shadow: none; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { AppScreen, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Card } from '../components/Card';
import { Button } from '../components/ui/Button';
import { RARITY_STATS, RARITY_SELL_VALUES } from '../constants';
import { fetchAnimeWallpaper } from '../utils/animeImageApi';
import { generateProceduralSkills, generateCardProfiles, generateProceduralDescription } from '../services/geminiService';

interface DeckScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const DeckScreen: React.FC<DeckScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [filter, setFilter] = useState<Rarity | 'ALL'>('ALL');
  const [selectedCard, setSelectedCard] = useState<CardData | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);
  }, []);

  const getImportRarity = (): Rarity => {
    const rand = Math.random();
    const importRates: [Rarity, number][] = [
      [Rarity.UR, 0.20],
      [Rarity.SSR, 0.30],
      [Rarity.SR, 0.30],
      [Rarity.R, 0.15],
      [Rarity.N, 0.05]
    ];

    let cumulative = 0;
    for (const [r, rate] of importRates) {
      cumulative += rate;
      if (rand <= cumulative) return r;
    }
    return Rarity.SR;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const result = event.target?.result as string;

      const elements = Object.values(ElementType);
      const element = elements[Math.floor(Math.random() * elements.length)];

      const rolledRarity = getImportRarity();
      const stats = RARITY_STATS[rolledRarity];
      const variance = () => (0.9 + Math.random() * 0.2);

      // Instant fetch via background object pool
      const profiles = await generateCardProfiles(1, [element]);
      const profile = profiles[0];
      const fallbackName = `Custom ${file.name.split('.')[0].substring(0, 10)}`;

      const newCard: CardData = {
        id: `custom_${Date.now()}_${Math.random().toString(36).substring(7)}`,
        name: profile?.name || fallbackName,
        rarity: rolledRarity,
        element: element,
        imageUrl: result,
        hp: Math.floor(stats.hp * variance()),
        maxHp: Math.floor(stats.hp * variance()),
        attack: Math.floor(stats.atk * variance()),
        defense: Math.floor(stats.def * variance()),
        description: profile?.description || generateProceduralDescription(element, profile?.name || fallbackName),
        isCustom: true,
        skills: profile?.skills || generateProceduralSkills(element, profile?.name || fallbackName)
      };

      setPlayerState(prev => ({
        ...prev,
        inventory: [newCard, ...prev.inventory]
      }));

      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  const handleSellCard = () => {
    if (!selectedCard) return;

    const sellValue = RARITY_SELL_VALUES[selectedCard.rarity];

    if (selectedCard.rarity === Rarity.UR || selectedCard.rarity === Rarity.SSR) {
       const confirmSell = window.confirm(`Are you absolutely sure you want to sell ${selectedCard.name}? This cannot be undone.`);
       if (!confirmSell) return;
    }

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits + sellValue,
      inventory: prev.inventory.filter(c => c.id !== selectedCard.id)
    }));

    setSelectedCard(null);
  };

  const filteredInventory = playerState.inventory.filter(c => filter === 'ALL' || c.rarity === filter);

  const rarityValues = { [Rarity.UR]: 5, [Rarity.SSR]: 4, [Rarity.SR]: 3, [Rarity.R]: 2, [Rarity.N]: 1 };
  filteredInventory.sort((a, b) => {
    if (rarityValues[b.rarity] !== rarityValues[a.rarity]) {
      return rarityValues[b.rarity] - rarityValues[a.rarity];
    }
    return b.id.localeCompare(a.id);
  });

  return (
    <div className="relative w-full h-full bg-slate-900 flex flex-col transform-gpu">
      {bgUrl && (
        <div 
          className="absolute inset-0 z-0 bg-cover bg-center opacity-20 mix-blend-overlay transition-all duration-1000 transform-gpu" 
          style={{ backgroundImage: `url(${bgUrl})` }}
        ></div>
      )}

      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="MY DECK" />

      <div className="relative z-10 flex-1 flex flex-col pt-24 px-8 pb-8 overflow-hidden transform-gpu will-change-transform">

        <div className="flex justify-between items-center mb-6 bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-xl transform-gpu">
          <div className="flex gap-2">
            {['ALL', Rarity.UR, Rarity.SSR, Rarity.SR, Rarity.R, Rarity.N].map(r => (
              <button 
                key={r}
                onClick={() => setFilter(r as any)}
                className={`px-4 py-1 rounded font-bold text-sm transform-gpu ${filter === r ? 'bg-blue-600 text-white' : 'bg-slate-700 text-gray-400 hover:bg-slate-600'}`}
              >
                {r}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <input 
              type="file" 
              accept="image/png, image/jpeg, image/gif" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
            />
            <Button variant="secondary" size="sm" onClick={() => fileInputRef.current?.click()}>
               IMPORT .GIF / .PNG
            </Button>
            <div className="text-gray-400 text-sm bg-black/50 px-3 py-1 rounded border border-white/10">
              Total Cards: <span className="text-white font-bold">{playerState.inventory.length}</span>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-4 pb-12 transform-gpu will-change-transform">
          {filteredInventory.length === 0 ? (
            <div className="h-full flex items-center justify-center text-gray-500 text-xl font-bold">
              NO CARDS FOUND
            </div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6 transform-gpu">
              {filteredInventory.map(card => (
                <Card 
                  key={card.id} 
                  card={card} 
                  size="sm" 
                  onClick={() => setSelectedCard(card)} 
                />
              ))}
            </div>
          )}
        </div>
      </div>

      {selectedCard && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-[fadeIn_0.1s_ease-out] transform-gpu">
           <div className="relative bg-slate-800 border-2 border-slate-600 rounded-3xl w-full max-w-5xl flex flex-col md:flex-row overflow-hidden shadow-[0_0_50px_rgba(0,0,0,0.8)] transform-gpu">

             <div className="md:w-1/2 bg-black flex items-center justify-center p-8 relative transform-gpu">
               <div className="absolute inset-0 bg-gradient-to-tr from-slate-900 via-transparent to-slate-800 opacity-50 transform-gpu"></div>
               <Card card={selectedCard} size="lg" className="z-10 shadow-2xl" is3D={true} />
             </div>

             <div className="md:w-1/2 p-8 flex flex-col max-h-[90vh] overflow-y-auto transform-gpu will-change-transform">
                <button 
                  onClick={() => setSelectedCard(null)}
                  className="absolute top-4 right-4 bg-slate-700 hover:bg-slate-500 text-white w-10 h-10 rounded-full font-bold flex items-center justify-center transition-colors z-20 shadow-lg"
                >
                  âś•
                </button>

                <div className="flex items-center justify-between mb-2 mt-4 md:mt-0">
                  <div className="flex items-center gap-3">
                    <span className={`px-3 py-1 rounded font-black text-sm ${selectedCard.rarity === Rarity.UR ? 'bg-red-500 text-white' : selectedCard.rarity === Rarity.SSR ? 'bg-yellow-500 text-black' : 'bg-blue-500 text-white'}`}>
                      {selectedCard.rarity}
                    </span>
                    <span className="bg-slate-700 px-3 py-1 rounded font-bold text-sm text-white">
                      {selectedCard.element}
                    </span>
                  </div>

                  <Button variant="danger" size="sm" onClick={handleSellCard} className="flex items-center gap-2">
                    SELL FOR <span className="text-yellow-300 font-black">{RARITY_SELL_VALUES[selectedCard.rarity]} C</span>
                  </Button>
                </div>

                <h2 className={`text-4xl font-black mb-4 uppercase tracking-wider ${selectedCard.rarity === Rarity.UR ? 'text-transparent bg-clip-text bg-gradient-to-r from-red-400 to-yellow-400' : 'text-white'}`}>
                  {selectedCard.name}
                </h2>

                <div className="bg-black/40 p-4 rounded-xl border border-white/10 mb-6 text-gray-300 italic">
                  "{selectedCard.description}"
                </div>

                <div className="grid grid-cols-3 gap-4 mb-6">
                  <div className="bg-green-900/40 border border-green-500/30 p-3 rounded-xl text-center">
                    <div className="text-gray-400 text-xs uppercase font-bold mb-1">Health</div>
                    <div className="text-green-400 font-black text-xl">{selectedCard.hp}</div>
                  </div>
                  <div className="bg-orange-900/40 border border-orange-500/30 p-3 rounded-xl text-center">
                    <div className="text-gray-400 text-xs uppercase font-bold mb-1">Attack</div>
                    <div className="text-orange-400 font-black text-xl">{selectedCard.attack}</div>
                  </div>
                  <div className="bg-blue-900/40 border border-blue-500/30 p-3 rounded-xl text-center">
                    <div className="text-gray-400 text-xs uppercase font-bold mb-1">Defense</div>
                    <div className="text-blue-400 font-black text-xl">{selectedCard.defense}</div>
                  </div>
                </div>

                <h3 className="text-xl font-black text-white mb-3 uppercase border-b border-gray-600 pb-2">Combat Skills</h3>
                <div className="space-y-3">
                  {(selectedCard.skills || generateProceduralSkills(selectedCard.element, selectedCard.name)).map(skill => (
                    <div key={skill.type} className="bg-slate-700/50 p-3 rounded-lg border border-slate-600">
                      <div className="flex justify-between items-center mb-1">
                        <span className="font-bold text-lg text-white">{skill.name}</span>
                        <span className="text-xs font-black uppercase tracking-wider text-gray-400 bg-black/50 px-2 py-1 rounded">{skill.type}</span>
                      </div>
                      <p className="text-sm text-gray-300">{skill.description}</p>
                    </div>
                  ))}
                </div>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills, generateProceduralName, generateProceduralDescription } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = () => {
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          if (parsed.date === today) {
            setBanner(parsed);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      // Optimistic Instant Load with Fallback while fetching
      const fallbackName1 = generateProceduralName();
      const fallbackName2 = generateProceduralName();
      const fallback: BannerData = {
        date: today,
        featuredCards: [
          { name: fallbackName1, rarity: Rarity.UR, element: ElementType.FIRE, description: generateProceduralDescription(ElementType.FIRE, fallbackName1), hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: 'https://picsum.photos/seed/fire/400/600', skills: generateProceduralSkills(ElementType.FIRE, fallbackName1) },
          { name: fallbackName2, rarity: Rarity.SSR, element: ElementType.WATER, description: generateProceduralDescription(ElementType.WATER, fallbackName2), hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: 'https://picsum.photos/seed/water/400/600', skills: generateProceduralSkills(ElementType.WATER, fallbackName2) }
        ]
      };
      setBanner(fallback);

      // Async fetch without blocking UI
      fetchDailyBanner().then(newBanner => {
         if (newBanner) {
            setBanner(newBanner);
            localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
         }
      });
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    let currentPity = playerState.pityCount;
    const baseCards: Partial<CardData>[] = [];
    const elementsToGenerate: ElementType[] = [];

    for (let i = 0; i < times; i++) {
      currentPity++;
      let forceUR = false;
      let forceSR = false;

      if (currentPity >= PITY_THRESHOLD) {
        forceUR = true;
        currentPity = 0;
      } else if (times === 10 && i === 9) {
        forceSR = true;
      }

      const card = determineCardStats(forceSR, forceUR);
      if (card.rarity === Rarity.UR) {
         currentPity = 0;
      }
      baseCards.push(card);

      if (!card.name && card.element) {
        elementsToGenerate.push(card.element);
      }
    }

    // Almost instant due to background object pool cache
    const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
    let profileIdx = 0;

    const newCards: CardData[] = await Promise.all(
      baseCards.map(async (c) => {
        if (c.name) {
           return c as CardData;
        }

        const profile = uniqueProfiles[profileIdx++];
        const finalName = profile?.name || generateProceduralName();
        const finalDescription = profile?.description || generateProceduralDescription(c.element as ElementType, finalName);
        const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType, finalName);
        const imageUrl = await getRandomAnimeImage(finalName + c.id);

        return { 
          ...c, 
          name: finalName, 
          description: finalDescription, 
          skills: finalSkills, 
          imageUrl 
        } as CardData;
      })
    );

    setPlayerState(prev => ({
      ...prev,
      credits: prev.credits - cost,
      pityCount: currentPity,
      inventory: [...prev.inventory, ...newCards]
    }));

    setPullResults(newCards);
    setIsRolling(false);
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col transform-gpu">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000 transform-gpu"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto transform-gpu will-change-transform">

        {!pullResults ? (
          <>
            {banner && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30 transform-gpu">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center transform-gpu">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group transform-gpu">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border transform-gpu ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity transform-gpu">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex flex-col items-center gap-6 mt-auto transform-gpu">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 transform-gpu"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible transform-gpu"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10 transform-gpu">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn transform-gpu">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg transform-gpu">SUMMON RESULTS</h2>
