import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD, FALLBACK_IMAGES } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills, generateProceduralName, generateProceduralDescription } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = () => {
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          // Safely check if the stored banner is valid
          if (parsed && parsed.date === today && Array.isArray(parsed.featuredCards)) {
            setBanner(parsed);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      // Optimistic Instant Load with High Quality Anime Fallbacks
      const fallbackName1 = generateProceduralName();
      const fallbackName2 = generateProceduralName();
      const fallback: BannerData = {
        date: today,
        featuredCards: [
          { name: fallbackName1, rarity: Rarity.UR, element: ElementType.FIRE, description: generateProceduralDescription(ElementType.FIRE, fallbackName1), hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: FALLBACK_IMAGES[0], skills: generateProceduralSkills(ElementType.FIRE, fallbackName1) },
          { name: fallbackName2, rarity: Rarity.SSR, element: ElementType.WATER, description: generateProceduralDescription(ElementType.WATER, fallbackName2), hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: FALLBACK_IMAGES[1], skills: generateProceduralSkills(ElementType.WATER, fallbackName2) }
        ]
      };
      setBanner(fallback);

      // Immediately spin up a background thread to fetch real anime images for the fallback characters
      getRandomAnimeImage(fallbackName1).then(img1 => {
        getRandomAnimeImage(fallbackName2).then(img2 => {
           setBanner(prev => {
              if (!prev || !prev.featuredCards || !prev.featuredCards[0] || prev.featuredCards[0].name !== fallbackName1) return prev;
              return {
                 ...prev,
                 featuredCards: [
                    { ...prev.featuredCards[0], imageUrl: img1 },
                    { ...prev.featuredCards[1], imageUrl: img2 }
                 ]
              };
           });
        });
      });

      // Async fetch full generative AI banner without blocking UI
      fetchDailyBanner().then(newBanner => {
         if (newBanner && newBanner.featuredCards) {
            setBanner(newBanner);
            localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
         }
      });
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner && banner.featuredCards && Array.isArray(banner.featuredCards)) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    try {
      let currentPity = playerState.pityCount;
      const baseCards: Partial<CardData>[] = [];
      const elementsToGenerate: ElementType[] = [];

      for (let i = 0; i < times; i++) {
        currentPity++;
        let forceUR = false;
        let forceSR = false;

        if (currentPity >= PITY_THRESHOLD) {
          forceUR = true;
          currentPity = 0;
        } else if (times === 10 && i === 9) {
          forceSR = true;
        }

        const card = determineCardStats(forceSR, forceUR);
        if (card.rarity === Rarity.UR) {
           currentPity = 0;
        }
        baseCards.push(card);

        if (!card.name && card.element) {
          elementsToGenerate.push(card.element);
        }
      }

      // Almost instant due to background object pool cache
      const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
      let profileIdx = 0;

      const newCards: CardData[] = await Promise.all(
        baseCards.map(async (c) => {
          if (c.name) {
             return c as CardData;
          }

          const profile = uniqueProfiles[profileIdx++];
          const finalName = profile?.name || generateProceduralName();
          const finalDescription = profile?.description || generateProceduralDescription(c.element as ElementType, finalName);
          const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType, finalName);
          const imageUrl = await getRandomAnimeImage(finalName + c.id);

          return { 
            ...c, 
            name: finalName, 
            description: finalDescription, 
            skills: finalSkills, 
            imageUrl 
          } as CardData;
        })
      );

      setPlayerState(prev => ({
        ...prev,
        credits: prev.credits - cost,
        pityCount: currentPity,
        inventory: [...newCards, ...prev.inventory]
      }));

      setPullResults(newCards);
    } catch (err) {
      console.error("Gacha pull encountered an error:", err);
      alert("There was a connection glitch summoning from the void. Please try again.");
    } finally {
      setIsRolling(false);
    }
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col transform-gpu">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000 transform-gpu"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto transform-gpu will-change-transform">

        {!pullResults ? (
          <>
            {banner && banner.featuredCards && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30 transform-gpu">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center transform-gpu">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group transform-gpu">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border transform-gpu ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity transform-gpu">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex flex-col items-center gap-6 mt-auto transform-gpu">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 transform-gpu"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible transform-gpu"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10 transform-gpu">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn transform-gpu">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg transform-gpu">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl transform-gpu">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake transform-gpu" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.2s_forwards] transform-gpu" />
                </div>
              ))}
            </div>
            <Button className="mt-12 transform-gpu" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.3s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn transform-gpu">
             <div className="flex flex-col items-center transform-gpu">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppScreen, PlayerState } from './types';
import { TitleScreen } from './screens/TitleScreen';
import { HomeScreen } from './screens/HomeScreen';
import { GachaScreen } from './screens/GachaScreen';
import { DeckScreen } from './screens/DeckScreen';
import { BattleScreen } from './screens/BattleScreen';

const defaultPlayerState: PlayerState = {
  credits: 1000,
  pityCount: 0,
  inventory: [],
  level: 1,
  exp: 0
};

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.TITLE);
  const [playerState, setPlayerState] = useState<PlayerState>(defaultPlayerState);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load state from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('playerState');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setPlayerState(prev => ({
          credits: typeof parsed.credits === 'number' ? parsed.credits : prev.credits,
          pityCount: typeof parsed.pityCount === 'number' ? parsed.pityCount : prev.pityCount,
          inventory: Array.isArray(parsed.inventory) ? parsed.inventory : prev.inventory,
          level: typeof parsed.level === 'number' ? parsed.level : prev.level,
          exp: typeof parsed.exp === 'number' ? parsed.exp : prev.exp
        }));
      } catch (e) {
        console.error("Failed to parse saved state");
      }
    }
    setIsLoaded(true);
  }, []);

  // Save state whenever it changes
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('playerState', JSON.stringify(playerState));
    }
  }, [playerState, isLoaded]);

  const changeScreen = (screen: AppScreen) => {
    setCurrentScreen(screen);
  };

  if (!isLoaded) return <div className="bg-black w-screen h-screen"></div>;

  return (
    <div className="w-full h-full font-sans antialiased text-white overflow-hidden bg-black selection:bg-blue-500/30">

      {currentScreen === AppScreen.TITLE && (
        <TitleScreen onStart={() => changeScreen(AppScreen.HOME)} />
      )}

      {currentScreen === AppScreen.HOME && (
        <HomeScreen playerState={playerState} changeScreen={changeScreen} />
      )}

      {currentScreen === AppScreen.GACHA && (
        <GachaScreen 
          playerState={playerState} 
          setPlayerState={setPlayerState} 
          changeScreen={changeScreen} 
        />
      )}

      {currentScreen === AppScreen.DECK && (
        <DeckScreen 
          playerState={playerState} 
          setPlayerState={setPlayerState} 
          changeScreen={changeScreen} 
        />
      )}

      {currentScreen === AppScreen.BATTLE && (
        <BattleScreen 
          playerState={playerState} 
          setPlayerState={setPlayerState} 
          changeScreen={changeScreen} 
        />
      )}

    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from '@google/genai';
import { BannerData, ElementType, Rarity, SkillType, Skill } from '../types';
import { getRandomAnimeImage } from '../utils/animeImageApi';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const cleanJSON = (text: string) => {
  let cleanText = text.trim();
  if (cleanText.startsWith('```json')) cleanText = cleanText.substring(7);
  if (cleanText.startsWith('```')) cleanText = cleanText.substring(3);
  if (cleanText.endsWith('```')) cleanText = cleanText.substring(0, cleanText.length - 3);
  return cleanText.trim();
};

// --- BACKGROUND AI POOLING ENGINE ---
// Uses CPU/Network in the background to pre-generate profiles, making UI responses INSTANT.
let profilePool: CardProfile[] = [];
let isFillingPool = false;

export const preloadAIProfiles = async () => {
  if (isFillingPool || profilePool.length > 15) return;
  isFillingPool = true;
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate exactly 5 unique anime character profiles with random elements (Fire, Water, Earth, Light, Dark). 
  For each character:
  1. Provide a highly unique, cool, and authentic Japanese Romaji name.
  2. Provide a short, epic character summary/lore description.
  3. Provide 4 epic and uniquely named combat skills that match their element: 1 basic attack, 1 heavy attack, 1 defensive move, and 1 ultimate move.
  4. Include a short description for what each skill does mechanically.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              basicAttackName: { type: Type.STRING },
              basicAttackDesc: { type: Type.STRING },
              heavyAttackName: { type: Type.STRING },
              heavyAttackDesc: { type: Type.STRING },
              defensiveSkillName: { type: Type.STRING },
              defensiveSkillDesc: { type: Type.STRING },
              ultimateSkillName: { type: Type.STRING },
              ultimateSkillDesc: { type: Type.STRING }
            },
            required: ["name", "description", "basicAttackName", "basicAttackDesc", "heavyAttackName", "heavyAttackDesc", "defensiveSkillName", "defensiveSkillDesc", "ultimateSkillName", "ultimateSkillDesc"]
          }
        }
      }
    });

    if (response.text) {
       const profiles = JSON.parse(cleanJSON(response.text));
       if (Array.isArray(profiles)) {
          const formatted = profiles.map((p: any) => ({
            name: p.name,
            description: p.description,
            skills: [
              { type: SkillType.BASIC, name: p.basicAttackName, description: p.basicAttackDesc },
              { type: SkillType.HEAVY, name: p.heavyAttackName, description: p.heavyAttackDesc },
              { type: SkillType.DEFEND, name: p.defensiveSkillName, description: p.defensiveSkillDesc },
              { type: SkillType.ULTIMATE, name: p.ultimateSkillName, description: p.ultimateSkillDesc }
            ]
          }));
          profilePool.push(...formatted);
       }
    }
  } catch (error: any) {
    console.warn("Background AI pre-fetch silent fail:", error);
  }
  isFillingPool = false;
};

// Trigger pool fill immediately on module load
preloadAIProfiles();


export const generateProceduralName = () => {
  const firstNames = ["Ryu", "Ken", "Akira", "Sora", "Kaito", "Haru", "Ren", "Yuki", "Shiro", "Kuro", "Hikaru", "Makoto", "Shin", "Zero", "Kage", "Jin", "Kazuya", "Ayame", "Sakura", "Hinata", "Kaori", "Misaki", "Rei", "Asuka", "Takeshi", "Hayate", "Ryuunosuke", "Kenshin", "Kagura", "Takeru", "Ryoko"];
  const lastNames = ["Kusanagi", "Kazama", "Mishima", "Yagami", "Shiramine", "Kurogane", "Aotsuki", "Akatsuki", "Mikazuchi", "Takahashi", "Suzuki", "Watanabe", "Yamamoto", "Nakamura", "Kobayashi", "Sasaki", "Matsumoto", "Inoue", "Himura", "Matoi", "Uzuki", "Amamiya"];
  const randSuffix = Math.random() > 0.85 ? ` ${['Prime', 'Alter', 'Zero', 'Omega', 'Kai'][Math.floor(Math.random()*5)]}` : '';

  const firstName = firstNames[Math.floor(Math.random() * firstNames.length)];
  const lastName = lastNames[Math.floor(Math.random() * lastNames.length)];

  return `${firstName} ${lastName}${randSuffix}`;
};

export const generateProceduralDescription = (element: ElementType, name: string): string => {
  const templates = [
    `A legendary ${element} warrior known for unmatched prowess on the battlefield. Few survive a direct encounter with ${name}.`,
    `Hailing from the hidden ${element} realms, ${name} strikes fear into the hearts of enemies with unpredictable tactics.`,
    `Armed with the ancient power of ${element}, this combatant bows to no one. They wander the shattered earth seeking worthy foes.`,
    `A wandering soul infused with volatile ${element} energy, seeking the ultimate challenge to test their limits.`,
    `Stories speak of a ${element} entity that single-handedly turned the tide of the Great War. That entity is undeniably ${name}.`,
    `Forged in the deepest, most treacherous parts of the ${element} domain, ${name} is considered an unstoppable force of nature.`,
    `Once a mere mortal, an anomaly in the matrix transformed them into a vessel of pure ${element} destruction.`
  ];
  return templates[Math.floor(Math.random() * templates.length)];
};

export const generateProceduralSkills = (element: ElementType, charName: string): Skill[] => {
  const elementalAdjectives: Record<ElementType, string[]> = {
    [ElementType.FIRE]: ["Infernal", "Scorching", "Blazing", "Volcanic", "Pyro", "Cinder", "Ash", "Sunflare", "Magma", "Ignis"],
    [ElementType.WATER]: ["Tidal", "Abyssal", "Glacial", "Hydro", "Crystal", "Frost", "Oceanic", "Leviathan", "Torrential", "Aqua"],
    [ElementType.EARTH]: ["Seismic", "Obsidian", "Terra", "Gaia", "Tectonic", "Bedrock", "Ironclad", "Meteor", "Geo", "Quake"],
    [ElementType.LIGHT]: ["Radiant", "Luminous", "Celestial", "Holy", "Divine", "Aurelian", "Prismatic", "Stellar", "Astral", "Halo"],
    [ElementType.DARK]: ["Umbral", "Void", "Abyssal", "Phantom", "Nether", "Shadow", "Eclipse", "Doom", "Onyx", "Stygian"]
  };

  const basicNouns = ["Strike", "Slash", "Bolt", "Dart", "Fang", "Claw", "Edge", "Pulse", "Whip", "Jab"];
  const heavyNouns = ["Buster", "Crash", "Impact", "Smash", "Breaker", "Crusher", "Driver", "Hammer", "Force", "Execution"];
  const defendNouns = ["Guard", "Shield", "Aegis", "Barrier", "Ward", "Phalanx", "Wall", "Veil", "Sanctuary", "Carapace"];
  const ultNouns = ["Nova", "Cataclysm", "Oblivion", "Genesis", "Requiem", "Annihilation", "Apocalypse", "Vortex", "Ragnarok", "Singularity"];

  const e = elementalAdjectives[element];
  const rand = (arr: string[]) => arr[Math.floor(Math.random() * arr.length)];

  const shortName = charName.split(' ')[0] || charName;

  return [
    { type: SkillType.BASIC, name: `${rand(e)} ${rand(basicNouns)}`, description: `Channels raw ${element} energy into a swift basic attack. Reliable and fast.` },
    { type: SkillType.HEAVY, name: `${shortName}'s ${rand(heavyNouns)}`, description: `A devastating, momentum-heavy blow that crushes enemy defenses dealing 1.8x damage. (2-turn CD)` },
    { type: SkillType.DEFEND, name: `${rand(e)} ${rand(defendNouns)}`, description: `Summons a dense protective aura of ${element}, granting a massive shield based on max HP. (2-turn CD)` },
    { type: SkillType.ULTIMATE, name: `Absolute ${rand(ultNouns)}`, description: `Unleashes the full terrifying potential of ${name}, obliterating the battlefield for 2.5x damage. (4-turn CD)` }
  ];
};

export interface CardProfile {
  name: string;
  description: string;
  skills: Skill[];
}

export const generateVictoryImage = async (name: string, element: ElementType, currentHp: number): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Anime style trading card of a victorious ${element} warrior named ${name}. The image should look like an epic celebratory end-of-battle screen. Include glowing text overlay clearly showing "VICTORY" and "${currentHp} HP". High quality, digital art, masterpiece.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    const parts = response.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Failed to generate victory image:", error);
  }
  return null;
};

export const fetchDailyBanner = async (): Promise<BannerData | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const today = new Date().toISOString().split('T')[0];

  const prompt = `
    Generate a new unique daily gacha banner featuring 2 anime-style characters.
    One must be of rarity "UR" (Ultra Rare) and one "SSR" (Super Super Rare).
    Give them highly unique, cool, and authentic Japanese Romaji names.
    Provide a short, epic character summary.
    Also provide 4 distinct skill names for each fitting their element.
    Provide realistic RPG stats based on rarity (UR: ~15000 HP, ~850 ATK, ~450 DEF. SSR: ~6000 HP, ~350 ATK, ~200 DEF).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              rarity: { type: Type.STRING },
              element: { type: Type.STRING },
              description: { type: Type.STRING },
              hp: { type: Type.INTEGER },
              attack: { type: Type.INTEGER },
              defense: { type: Type.INTEGER },
              skillBasicName: { type: Type.STRING },
              skillBasicDesc: { type: Type.STRING },
              skillHeavyName: { type: Type.STRING },
              skillHeavyDesc: { type: Type.STRING },
              skillDefendName: { type: Type.STRING },
              skillDefendDesc: { type: Type.STRING },
              skillUltimateName: { type: Type.STRING },
              skillUltimateDesc: { type: Type.STRING }
            },
            required: ["name", "rarity", "element", "description", "hp", "attack", "defense", "skillBasicName", "skillBasicDesc", "skillHeavyName", "skillHeavyDesc", "skillDefendName", "skillDefendDesc", "skillUltimateName", "skillUltimateDesc"]
          }
        }
      }
    });

    if (response.text) {
      const parsed = JSON.parse(cleanJSON(response.text));
      const featuredCards = await Promise.all(parsed.map(async (c: any) => {
        const el = Object.values(ElementType).includes(c.element) ? c.element as ElementType : ElementType.LIGHT;
        return {
          name: c.name,
          rarity: c.rarity as Rarity,
          element: el,
          description: c.description,
          hp: c.hp,
          maxHp: c.hp,
          attack: c.attack,
          defense: c.defense,
          imageUrl: await getRandomAnimeImage(c.name),
          skills: [
            { type: SkillType.BASIC, name: c.skillBasicName, description: c.skillBasicDesc },
            { type: SkillType.HEAVY, name: c.skillHeavyName, description: c.skillHeavyDesc },
            { type: SkillType.DEFEND, name: c.skillDefendName, description: c.skillDefendDesc },
            { type: SkillType.ULTIMATE, name: c.skillUltimateName, description: c.skillUltimateDesc }
          ]
        };
      }));
      return { date: today, featuredCards };
    }
  } catch (error: any) {
    console.warn("Failed to generate banner", error);
  }
  return null;
};

// NOW INSTANT: Uses the pre-generated background pool or local procedural generator instantly
export const generateCardProfiles = async (count: number, elements: ElementType[]): Promise<CardProfile[]> => {
  // Trigger pool refill asynchronously in background
  if (profilePool.length < 5) preloadAIProfiles();

  const results: CardProfile[] = [];
  for (let i = 0; i < count; i++) {
    const el = elements[i] || ElementType.LIGHT;

    // Attempt to pull a high-quality pre-generated profile from pool
    if (profilePool.length > 0) {
      const profile = profilePool.shift()!;
      results.push(profile);
    } else {
      // Instant Local Procedural Fallback if pool is empty
      const name = generateProceduralName();
      results.push({
        name,
        description: generateProceduralDescription(el, name),
        skills: generateProceduralSkills(el, name)
      });
    }
  }
  return results;
};

import React, { useState, useEffect } from 'react';
import { AppScreen, BannerData, CardData, PlayerState, Rarity, ElementType } from '../types';
import { TopBar } from '../components/ui/TopBar';
import { Button } from '../components/ui/Button';
import { Card } from '../components/Card';
import { GACHA_COST_SINGLE, GACHA_COST_TEN, RARITY_RATES, RARITY_STATS, PITY_THRESHOLD, FALLBACK_IMAGES } from '../constants';
import { fetchDailyBanner, generateCardProfiles, generateProceduralSkills, generateProceduralName, generateProceduralDescription } from '../services/geminiService';
import { getRandomAnimeImage, fetchAnimeWallpaper } from '../utils/animeImageApi';

interface GachaScreenProps {
  playerState: PlayerState;
  setPlayerState: React.Dispatch<React.SetStateAction<PlayerState>>;
  changeScreen: (screen: AppScreen) => void;
}

export const GachaScreen: React.FC<GachaScreenProps> = ({ playerState, setPlayerState, changeScreen }) => {
  const [banner, setBanner] = useState<BannerData | null>(null);
  const [pullResults, setPullResults] = useState<CardData[] | null>(null);
  const [isRolling, setIsRolling] = useState(false);
  const [bgUrl, setBgUrl] = useState('');

  useEffect(() => {
    fetchAnimeWallpaper().then(setBgUrl);

    const initBanner = () => {
      const today = new Date().toISOString().split('T')[0];
      const storedBanner = localStorage.getItem('dailyBanner');

      if (storedBanner) {
        try {
          const parsed = JSON.parse(storedBanner);
          // Safely check if the stored banner is valid
          if (parsed && parsed.date === today && Array.isArray(parsed.featuredCards) && parsed.featuredCards.length > 0) {
            setBanner(parsed);
            return;
          }
        } catch (e) {
          console.error("Stored banner parse error");
        }
      }

      // Optimistic Instant Load with High Quality Anime Fallbacks
      const fallbackName1 = generateProceduralName();
      const fallbackName2 = generateProceduralName();
      const fallback: BannerData = {
        date: today,
        featuredCards: [
          { name: fallbackName1, rarity: Rarity.UR, element: ElementType.FIRE, description: generateProceduralDescription(ElementType.FIRE, fallbackName1), hp: 15000, maxHp: 15000, attack: 950, defense: 450, imageUrl: FALLBACK_IMAGES[0], skills: generateProceduralSkills(ElementType.FIRE, fallbackName1) },
          { name: fallbackName2, rarity: Rarity.SSR, element: ElementType.WATER, description: generateProceduralDescription(ElementType.WATER, fallbackName2), hp: 6000, maxHp: 6000, attack: 400, defense: 200, imageUrl: FALLBACK_IMAGES[1], skills: generateProceduralSkills(ElementType.WATER, fallbackName2) }
        ]
      };
      setBanner(fallback);

      // Immediately spin up a background thread to fetch real anime images for the fallback characters
      getRandomAnimeImage(fallbackName1).then(img1 => {
        getRandomAnimeImage(fallbackName2).then(img2 => {
           setBanner(prev => {
              if (!prev || !prev.featuredCards || !prev.featuredCards[0] || prev.featuredCards[0].name !== fallbackName1) return prev;
              return {
                 ...prev,
                 featuredCards: [
                    { ...prev.featuredCards[0], imageUrl: img1 },
                    { ...prev.featuredCards[1], imageUrl: img2 }
                 ]
              };
           });
        });
      });

      // Async fetch full generative AI banner without blocking UI
      fetchDailyBanner().then(newBanner => {
         if (newBanner && newBanner.featuredCards && newBanner.featuredCards.length > 0) {
            setBanner(newBanner);
            localStorage.setItem('dailyBanner', JSON.stringify(newBanner));
         }
      });
    };

    initBanner();
  }, []);

  const determineCardStats = (forceSRorHigher = false, forceUR = false): Partial<CardData> => {
    let rollRarity = Rarity.N;

    if (forceUR) {
      rollRarity = Rarity.UR;
    } else {
      const rand = Math.random();
      let cumulative = 0;

      const rates = forceSRorHigher 
        ? { [Rarity.UR]: 0.05, [Rarity.SSR]: 0.25, [Rarity.SR]: 0.70, [Rarity.R]: 0, [Rarity.N]: 0 } 
        : RARITY_RATES;

      for (const [r, rate] of Object.entries(rates)) {
        cumulative += rate;
        if (rand <= cumulative) {
          rollRarity = r as Rarity;
          break;
        }
      }
    }

    if (banner && banner.featuredCards && Array.isArray(banner.featuredCards)) {
      const featured = banner.featuredCards.find(c => c.rarity === rollRarity);
      if (featured) {
         if (Math.random() > 0.5) {
            return {
              ...featured,
              id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`
            };
         }
      }
    }

    const elements = Object.values(ElementType);
    const element = elements[Math.floor(Math.random() * elements.length)];
    const stats = RARITY_STATS[rollRarity];
    const variance = () => (0.9 + Math.random() * 0.2);

    return {
      id: `card_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      rarity: rollRarity,
      element,
      hp: Math.floor(stats.hp * variance()),
      maxHp: Math.floor(stats.hp * variance()),
      attack: Math.floor(stats.atk * variance()),
      defense: Math.floor(stats.def * variance()),
    };
  };

  const handlePull = async (times: number) => {
    const cost = times === 1 ? GACHA_COST_SINGLE : GACHA_COST_TEN;
    if (playerState.credits < cost) {
      alert("Not enough credits!");
      return;
    }

    setIsRolling(true);
    setPullResults(null);

    try {
      let currentPity = playerState.pityCount;
      const baseCards: Partial<CardData>[] = [];
      const elementsToGenerate: ElementType[] = [];

      for (let i = 0; i < times; i++) {
        currentPity++;
        let forceUR = false;
        let forceSR = false;

        if (currentPity >= PITY_THRESHOLD) {
          forceUR = true;
          currentPity = 0;
        } else if (times === 10 && i === 9) {
          forceSR = true;
        }

        const card = determineCardStats(forceSR, forceUR);
        if (card.rarity === Rarity.UR) {
           currentPity = 0;
        }
        baseCards.push(card);

        if (!card.name && card.element) {
          elementsToGenerate.push(card.element);
        }
      }

      // Almost instant due to background object pool cache
      const uniqueProfiles = await generateCardProfiles(elementsToGenerate.length, elementsToGenerate);
      let profileIdx = 0;

      const newCards: CardData[] = await Promise.all(
        baseCards.map(async (c) => {
          if (c.name) {
             return c as CardData;
          }

          const profile = uniqueProfiles[profileIdx++];
          const finalName = profile?.name || generateProceduralName();
          const finalDescription = profile?.description || generateProceduralDescription(c.element as ElementType, finalName);
          const finalSkills = profile?.skills || generateProceduralSkills(c.element as ElementType, finalName);
          const imageUrl = await getRandomAnimeImage(finalName + c.id);

          return { 
            ...c, 
            name: finalName, 
            description: finalDescription, 
            skills: finalSkills, 
            imageUrl 
          } as CardData;
        })
      );

      setPlayerState(prev => ({
        ...prev,
        credits: prev.credits - cost,
        pityCount: currentPity,
        inventory: [...newCards, ...prev.inventory]
      }));

      setPullResults(newCards);
    } catch (err) {
      console.error("Gacha pull encountered an error:", err);
      alert("There was a connection glitch summoning from the void. Please try again.");
    } finally {
      setIsRolling(false);
    }
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden flex flex-col transform-gpu">
      <TopBar playerState={playerState} onBack={() => changeScreen(AppScreen.HOME)} title="SUMMON" />

      <div 
        className="absolute inset-0 z-0 bg-cover opacity-20 bg-center animate-pulse-fast mix-blend-screen transition-all duration-1000 transform-gpu"
        style={{ backgroundImage: bgUrl ? `url(${bgUrl})` : undefined }}
      ></div>

      <div className="relative z-10 flex-1 flex flex-col items-center justify-center pt-24 pb-8 px-4 w-full max-w-7xl mx-auto transform-gpu will-change-transform">

        {!pullResults ? (
          <>
            {banner && banner.featuredCards && banner.featuredCards.length > 0 && (
              <div className="w-full flex flex-col items-center mb-12">
                <div className="bg-gradient-to-r from-transparent via-red-900/50 to-transparent w-full py-4 text-center mb-8 border-y border-red-500/30 transform-gpu">
                   <h2 className="text-3xl font-black text-yellow-400 tracking-widest uppercase drop-shadow-[0_0_10px_rgba(234,179,8,0.8)]">
                     LIMITED TIME: DESTINY AWAKENS
                   </h2>
                   <p className="text-red-200 text-sm mt-1">Refreshes every 24 hours. AI Generated.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-12 items-center justify-center transform-gpu">
                  {banner.featuredCards.map((card, idx) => (
                    <div key={idx} className="flex flex-col items-center group transform-gpu">
                      <div className="mb-4 text-center">
                        <span className={`text-lg font-bold px-3 py-1 rounded bg-black/60 border transform-gpu ${card.rarity === Rarity.UR ? 'text-red-400 border-red-500' : 'text-yellow-400 border-yellow-500'}`}>
                          RATE UP {card.rarity}
                        </span>
                      </div>
                      <Card card={{...card, id: 'display'}} size="lg" is3D={true} />
                      <div className="max-w-xs text-center mt-4 bg-black/60 p-3 rounded text-sm text-gray-300 backdrop-blur-sm border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity transform-gpu">
                         "{card.description}"
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex flex-col items-center gap-6 mt-auto transform-gpu">
               <div className="flex gap-8">
                 <Button 
                    variant="secondary" 
                    size="lg" 
                    onClick={() => handlePull(1)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 transform-gpu"
                  >
                   <span>1x PULL</span>
                   <span className="text-sm font-normal text-yellow-400">100 Credits</span>
                 </Button>

                 <Button 
                    variant="gold" 
                    size="lg" 
                    onClick={() => handlePull(10)}
                    disabled={isRolling}
                    className="w-48 flex flex-col items-center gap-1 relative overflow-visible transform-gpu"
                  >
                   <div className="absolute -top-3 -right-3 bg-red-600 text-white text-xs font-black px-2 py-1 rounded transform rotate-12 shadow-lg z-20 border border-white">
                     GUARANTEED SR!
                   </div>
                   <span>10x PULL</span>
                   <span className="text-sm font-normal text-yellow-100">1000 Credits</span>
                 </Button>
               </div>

               <div className="bg-black/50 px-6 py-2 rounded-full border border-white/10 transform-gpu">
                 <span className="text-gray-400">Pity Counter: </span>
                 <span className="text-white font-bold">{playerState.pityCount} / {PITY_THRESHOLD}</span>
                 <span className="text-xs text-gray-500 ml-2">(UR Guaranteed at {PITY_THRESHOLD})</span>
               </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center animate-fadeIn transform-gpu">
            <h2 className="text-4xl font-black mb-12 text-white tracking-widest drop-shadow-lg transform-gpu">SUMMON RESULTS</h2>
            <div className="flex flex-wrap justify-center gap-4 max-w-5xl transform-gpu">
              {pullResults.map((card, idx) => (
                <div key={card.id} className="animate-shake transform-gpu" style={{ animationDelay: `${idx * 0.1}s`, animationIterationCount: 1 }}>
                  <Card card={card} size="md" className="transform scale-0 animate-[scaleIn_0.2s_forwards] transform-gpu" />
                </div>
              ))}
            </div>
            <Button className="mt-12 transform-gpu" onClick={() => setPullResults(null)}>
              CONFIRM
            </Button>
            <style>{`
              @keyframes scaleIn {
                to { transform: scale(1); }
              }
              .animate-fadeIn {
                animation: fadeIn 0.3s ease-out;
              }
              @keyframes fadeIn {
                from { opacity: 0; }
                to { opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {isRolling && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center animate-fadeIn transform-gpu">
             <div className="flex flex-col items-center transform-gpu">
               <div className="text-6xl animate-spin-slow mb-4">âś¨</div>
               <div className="text-xl font-bold tracking-widest uppercase animate-pulse">Summoning from the void...</div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

