              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <input 
              type="file" 
              accept="image/png, image/jpeg, image/gif" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleFileUpload}
            />
            <Button variant="gold" size="sm" onClick={() => fileInputRef.current?.click()} disabled={isImporting}>
               {isImporting ? 'ANALYZING GIF...' : 'IMPORT GIF / IMG'}
            </Button>
            <div className="text-gray-400 text-sm bg-black/50 px-3 py-2 rounded-lg border border-white/10">
              Total: <span className="text-white font-bold">{playerState.inventory.length}</span>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pr-4 pb-12 transform-gpu will-change-transform">
          {filteredInventory.length === 0 ? (
            <div className="h-full flex items-center justify-center text-gray-500 text-xl font-bold italic tracking-widest opacity-30">
              [ NO WARRIORS IN CRYOSLEEP ]
            </div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6 transform-gpu">
              {filteredInventory.map(card => (
